import { NextResponse } from "next/server";
import { Types } from "mongoose";
import { z } from "zod";

import { connectToDatabase } from "@/lib/db/connect";
import { SavedRequestModel } from "@/lib/db/models/SavedRequest";
import { EnvironmentModel } from "@/lib/db/models/Environment";
import { RunResultModel } from "@/lib/db/models/RunResult";
import { apiError, apiException, readJsonBody, headersToRecord, normalizeHeaders, parseObjectId } from "@/lib/server/api";
import { getTenantContext } from "@/lib/server/auth";
import { normalizeAuthConfig, createDefaultAuthConfig, normalizeBodyMode, normalizeBodyForm } from "@/lib/server/request-contract";
import { interpolateString, interpolateHeaders, interpolateKeyValuePairs, variablesToMap } from "@/lib/server/interpolate";
import { executeScript } from "@/lib/scripting/pm-api";
import type { TestResult } from "@/types";

export const runtime = "nodejs";

const runSchema = z.object({
  collection_id: z.string().trim().min(1),
  environment_id: z.string().trim().optional().nullable(),
  iterations: z.number().int().min(1).max(100).default(1),
  delay_ms: z.number().int().min(0).max(10000).default(0),
});

export async function POST(request: Request) {
  const context = await getTenantContext();
  if (!context) return apiError("Unauthorized.", 401);

  try {
    const payload = await readJsonBody<unknown>(request);
    const parsed = runSchema.safeParse(payload);
    if (!parsed.success) return apiError("Invalid payload.", 422, "VALIDATION_ERROR", parsed.error.flatten());

    await connectToDatabase();

    const collectionId = parseObjectId(parsed.data.collection_id);
    if (!collectionId) return apiError("Invalid collection ID.", 422);

    const envId = parseObjectId(parsed.data.environment_id ?? null);
    let variableMap: Record<string, string> = {};

    if (envId) {
      const env = await EnvironmentModel.findOne({ _id: envId, tenant_id: context.tenantId }).lean();
      if (env) variableMap = variablesToMap(env.variables);
    }

    const requests = await SavedRequestModel.find({
      collection_id: collectionId,
      tenant_id: context.tenantId,
    })
      .sort({ sort_order: 1, createdAt: 1 })
      .lean();

    const results: {
      iteration: number;
      request_id: string;
      request_name: string;
      method: string;
      url: string;
      status: number | null;
      duration_ms: number;
      passed: boolean;
      error: string | null;
      test_results: TestResult[];
    }[] = [];

    let totalPassed = 0;
    let totalFailed = 0;
    const startedAt = new Date();

    for (let iter = 1; iter <= parsed.data.iterations; iter++) {
      for (const req of requests) {
        const interpolatedUrl = interpolateString(req.url, variableMap);
        const normalizedHeaders = normalizeHeaders(req.headers ?? []);
        const interpolatedHeaders = interpolateHeaders(normalizedHeaders, variableMap);
        const headersRecord = headersToRecord(interpolatedHeaders);
        const bodyMode = normalizeBodyMode(req.body_mode, req.method);
        const rawBody = interpolateString(req.body_raw ?? req.body ?? "", variableMap);

        let bodyToSend: BodyInit | undefined;
        if (bodyMode === "raw" && rawBody.trim()) {
          bodyToSend = rawBody;
        } else if (bodyMode === "x-www-form-urlencoded") {
          const formPairs = interpolateKeyValuePairs(normalizeBodyForm(req.body_form), variableMap).filter((f) => f.enabled !== false);
          const params = new URLSearchParams();
          formPairs.forEach((f) => params.append(f.key, f.value));
          bodyToSend = params;
        }

        const start = Date.now();
        let status: number | null = null;
        let error: string | null = null;
        let responseBody = "";
        let responseHeaders: { key: string; value: string }[] = [];

        try {
          const parsedUrl = new URL(interpolatedUrl);
          const auth = normalizeAuthConfig(req.auth ?? createDefaultAuthConfig());
          let finalHeaders = { ...headersRecord };

          if (auth.type === "bearer" && auth.bearerToken) {
            finalHeaders.Authorization = `Bearer ${interpolateString(auth.bearerToken, variableMap)}`;
          } else if (auth.type === "basic") {
            const token = Buffer.from(`${interpolateString(auth.basic.username, variableMap)}:${interpolateString(auth.basic.password, variableMap)}`).toString("base64");
            finalHeaders.Authorization = `Basic ${token}`;
          }

          const controller = new AbortController();
          const timeout = setTimeout(() => controller.abort(), 30000);

          const resp = await fetch(parsedUrl.toString(), {
            method: req.method,
            headers: finalHeaders,
            body: bodyToSend,
            cache: "no-store",
            signal: controller.signal,
          });

          clearTimeout(timeout);
          status = resp.status;
          responseBody = await resp.text();
          resp.headers.forEach((v, k) => responseHeaders.push({ key: k, value: v }));
        } catch (err) {
          error = err instanceof Error ? err.message : String(err);
        }

        const durationMs = Date.now() - start;

        // Run test scripts
        let testResults: TestResult[] = [];
        const testScript = req.test_script ?? "";
        if (testScript.trim() && status !== null) {
          const scriptResult = executeScript(testScript, {
            response: { status, statusText: "", headers: responseHeaders, body: responseBody, durationMs },
            envVariables: variableMap,
          });
          testResults = scriptResult.testResults;
        }

        const allPassed = !error && (status !== null && status < 400) && testResults.every((t) => t.passed);
        if (allPassed) totalPassed++;
        else totalFailed++;

        results.push({
          iteration: iter,
          request_id: req._id.toString(),
          request_name: req.name,
          method: req.method,
          url: interpolatedUrl,
          status,
          duration_ms: durationMs,
          passed: allPassed,
          error,
          test_results: testResults,
        });

        // Delay between requests
        if (parsed.data.delay_ms > 0) {
          await new Promise((resolve) => setTimeout(resolve, parsed.data.delay_ms));
        }
      }
    }

    const total = totalPassed + totalFailed;
    const runDoc = await RunResultModel.create({
      _id: new Types.ObjectId(),
      tenant_id: context.tenantId,
      collection_id: collectionId,
      environment_id: envId,
      total,
      passed: totalPassed,
      failed: totalFailed,
      iterations: parsed.data.iterations,
      delay_ms: parsed.data.delay_ms,
      status: "completed",
      results,
      started_at: startedAt,
      completed_at: new Date(),
    });

    return NextResponse.json({
      run: {
        id: runDoc._id.toString(),
        total,
        passed: totalPassed,
        failed: totalFailed,
        iterations: parsed.data.iterations,
        status: "completed",
        results,
      },
    });
  } catch (error) {
    return apiException(error);
  }
}

"use client";

import { use, useEffect, useMemo, useState, type ReactElement } from "react";
import Link from "next/link";
import type { KeyValuePair, RequestAuthConfig } from "@/types";

export const dynamic = "force-dynamic";

interface SharedCollectionInfo {
  id: string;
  name: string;
  description?: string;
  slug: string;
}

interface SharedFolder {
  id: string;
  collectionId: string | null;
  parentId: string | null;
  name: string;
  description?: string;
}

interface SharedRequest {
  id: string;
  collectionId: string | null;
  folderId: string | null;
  name: string;
  description?: string;
  method: string;
  url: string;
  headers?: KeyValuePair[];
  bodyMode?: string;
  bodyRaw?: string;
  bodyForm?: KeyValuePair[];
  auth?: RequestAuthConfig;
  body?: string;
}

interface SharedPayload {
  schemaVersion: number;
  exportedAt: string;
  shared: boolean;
  collection: SharedCollectionInfo;
  folders: SharedFolder[];
  requests: SharedRequest[];
}

type SelectedNode =
  | { type: "collection" }
  | { type: "folder"; folderId: string }
  | { type: "request"; requestId: string };

type GroupTab = "overview" | "authorization" | "variables";
type RequestTab = "overview" | "authorization" | "headers" | "body";

function methodColor(method: string): string {
  switch ((method || "").toUpperCase()) {
    case "GET":
      return "#61affe";
    case "POST":
      return "#49cc90";
    case "PUT":
      return "#fca130";
    case "PATCH":
      return "#50e3c2";
    case "DELETE":
      return "#f93e3e";
    default:
      return "#999";
  }
}

function parseQueryParams(rawUrl: string): Array<{ key: string; value: string }> {
  const queryIndex = rawUrl.indexOf("?");
  if (queryIndex === -1) {
    return [];
  }

  const hashIndex = rawUrl.indexOf("#");
  const query = rawUrl.slice(queryIndex + 1, hashIndex > -1 ? hashIndex : undefined);

  return query
    .split("&")
    .filter(Boolean)
    .map((chunk) => {
      const equals = chunk.indexOf("=");
      if (equals === -1) {
        return { key: decodeURIComponent(chunk), value: "" };
      }
      return {
        key: decodeURIComponent(chunk.slice(0, equals)),
        value: decodeURIComponent(chunk.slice(equals + 1)),
      };
    });
}

function normalizeAuth(auth: SharedRequest["auth"]): RequestAuthConfig {
  if (!auth) {
    return {
      type: "none",
      basic: { username: "", password: "" },
      bearerToken: "",
      apiKey: { key: "", value: "", addTo: "header" },
    };
  }
  return auth;
}

function parsePostmanUrl(raw: string): { raw: string; host: string[]; protocol?: string; port?: string; path?: string[]; query?: Array<{ key: string; value: string }> } {
  const safeRaw = raw?.trim() || "";

  const envMatch = safeRaw.match(/^(\{\{[^}]+\}\})(\/[^?#]*)?([?#].*)?$/);
  if (envMatch) {
    const hostVar = envMatch[1];
    const pathStr = envMatch[2] ?? "";
    const queryStr = envMatch[3] ?? "";
    const path = pathStr.replace(/^\//, "").split("/").filter(Boolean);
    const query = queryStr.startsWith("?")
      ? queryStr
          .slice(1)
          .split("&")
          .filter(Boolean)
          .map((entry) => {
            const equal = entry.indexOf("=");
            return equal === -1
              ? { key: entry, value: "" }
              : { key: entry.slice(0, equal), value: entry.slice(equal + 1) };
          })
      : [];

    return {
      raw: safeRaw,
      host: [hostVar],
      ...(path.length > 0 ? { path } : {}),
      ...(query.length > 0 ? { query } : {}),
    };
  }

  try {
    const parsed = new URL(safeRaw);
    const path = parsed.pathname.replace(/^\//, "").split("/").filter(Boolean);
    const query: Array<{ key: string; value: string }> = [];
    parsed.searchParams.forEach((value, key) => query.push({ key, value }));

    return {
      raw: safeRaw,
      protocol: parsed.protocol.replace(":", ""),
      host: parsed.hostname.split("."),
      ...(parsed.port ? { port: parsed.port } : {}),
      ...(path.length > 0 ? { path } : {}),
      ...(query.length > 0 ? { query } : {}),
    };
  } catch {
    return { raw: safeRaw, host: [safeRaw] };
  }
}

function toPostmanAuth(auth: RequestAuthConfig):
  | { type: "noauth" }
  | { type: "basic"; basic: { key: string; value: string; type: string }[] }
  | { type: "bearer"; bearer: { key: string; value: string; type: string }[] }
  | { type: "apikey"; apikey: { key: string; value: string; type: string }[] } {
  if (auth.type === "basic") {
    return {
      type: "basic",
      basic: [
        { key: "username", value: auth.basic.username, type: "string" },
        { key: "password", value: auth.basic.password, type: "string" },
      ],
    };
  }
  if (auth.type === "bearer") {
    return {
      type: "bearer",
      bearer: [{ key: "token", value: auth.bearerToken, type: "string" }],
    };
  }
  if (auth.type === "api-key") {
    return {
      type: "apikey",
      apikey: [
        { key: "key", value: auth.apiKey.key, type: "string" },
        { key: "value", value: auth.apiKey.value, type: "string" },
        { key: "in", value: auth.apiKey.addTo === "query" ? "query" : "header", type: "string" },
      ],
    };
  }

  return { type: "noauth" };
}

function toPostmanBody(request: SharedRequest):
  | { mode: "raw"; raw: string }
  | { mode: "formdata"; formdata: { key: string; value: string; disabled?: boolean; type: "text" }[] }
  | { mode: "urlencoded"; urlencoded: { key: string; value: string; disabled?: boolean }[] }
  | undefined {
  const mode = request.bodyMode ?? "raw";

  if (mode === "raw") {
    return { mode: "raw", raw: request.bodyRaw ?? request.body ?? "" };
  }

  if (mode === "form-data") {
    return {
      mode: "formdata",
      formdata: (request.bodyForm ?? [])
        .filter((item) => Boolean(item.key))
        .map((item) => ({
          key: item.key,
          value: item.value,
          disabled: item.enabled === false ? true : undefined,
          type: "text",
        })),
    };
  }

  if (mode === "x-www-form-urlencoded") {
    return {
      mode: "urlencoded",
      urlencoded: (request.bodyForm ?? [])
        .filter((item) => Boolean(item.key))
        .map((item) => ({
          key: item.key,
          value: item.value,
          disabled: item.enabled === false ? true : undefined,
        })),
    };
  }

  return undefined;
}

function buildPostmanCollection(payload: SharedPayload): Record<string, unknown> {
  const rootFolders = payload.folders.filter((folder) => folder.parentId === null);
  const rootRequests = payload.requests.filter((request) => request.folderId === null);

  function buildRequestItem(request: SharedRequest): Record<string, unknown> {
    const body = toPostmanBody(request);
    return {
      name: request.name,
      request: {
        method: request.method.toUpperCase(),
        header: (request.headers ?? []).filter((item) => Boolean(item.key)).map((item) => ({
          key: item.key,
          value: item.value,
          disabled: item.enabled === false ? true : undefined,
        })),
        ...(body ? { body } : {}),
        url: parsePostmanUrl(request.url),
        auth: toPostmanAuth(normalizeAuth(request.auth)),
        ...(request.description ? { description: request.description } : {}),
      },
      response: [],
    };
  }

  function buildFolderItem(folder: SharedFolder): Record<string, unknown> {
    const childFolders = payload.folders.filter((item) => item.parentId === folder.id);
    const childRequests = payload.requests.filter((item) => item.folderId === folder.id);
    return {
      name: folder.name,
      ...(folder.description ? { description: folder.description } : {}),
      item: [
        ...childFolders.map((item) => buildFolderItem(item)),
        ...childRequests.map((item) => buildRequestItem(item)),
      ],
    };
  }

  return {
    info: {
      name: payload.collection.name,
      description: payload.collection.description ?? "",
      schema: "https://schema.getpostman.com/json/collection/v2.1.0/collection.json",
    },
    item: [
      ...rootFolders.map((folder) => buildFolderItem(folder)),
      ...rootRequests.map((request) => buildRequestItem(request)),
    ],
  };
}

export default function SharedCollectionPage({ params }: { params: Promise<{ slug: string }> }): ReactElement {
  const { slug } = use(params);

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [payload, setPayload] = useState<SharedPayload | null>(null);
  const [selected, setSelected] = useState<SelectedNode>({ type: "collection" });
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set());
  const [groupTab, setGroupTab] = useState<GroupTab>("overview");
  const [requestTab, setRequestTab] = useState<RequestTab>("overview");

  useEffect(() => {
    let active = true;

    async function loadSharedCollection() {
      setLoading(true);
      setError(null);

      try {
        const response = await fetch(`/api/share/${slug}`, { cache: "no-store" });
        const body = (await response.json().catch(() => null)) as { data?: SharedPayload; error?: string } | null;
        if (!response.ok || !body?.data) {
          throw new Error(body?.error || "Shared collection not found.");
        }

        if (!active) {
          return;
        }

        setPayload(body.data);
        setSelected({ type: "collection" });
        setExpandedFolders(
          new Set(
            body.data.folders
              .filter((folder) => folder.parentId === null)
              .map((folder) => folder.id),
          ),
        );
      } catch (loadError) {
        if (!active) {
          return;
        }
        const message = loadError instanceof Error ? loadError.message : "Unable to load shared collection.";
        setPayload(null);
        setError(message);
      } finally {
        if (active) {
          setLoading(false);
        }
      }
    }

    void loadSharedCollection();
    return () => {
      active = false;
    };
  }, [slug]);

  const selectedFolder = useMemo(
    () => (selected.type === "folder" ? payload?.folders.find((folder) => folder.id === selected.folderId) ?? null : null),
    [payload?.folders, selected],
  );

  const selectedRequest = useMemo(
    () => (selected.type === "request" ? payload?.requests.find((request) => request.id === selected.requestId) ?? null : null),
    [payload?.requests, selected],
  );

  function toggleFolder(folderId: string) {
    setExpandedFolders((current) => {
      const next = new Set(current);
      if (next.has(folderId)) {
        next.delete(folderId);
      } else {
        next.add(folderId);
      }
      return next;
    });
  }

  async function handleDownload() {
    if (!payload) {
      return;
    }

    try {
      const postmanCollection = buildPostmanCollection(payload);
      const blob = new Blob([JSON.stringify(postmanCollection, null, 2)], { type: "application/json" });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = `${payload.collection.name || "shared-collection"}.postman_collection.json`;
      document.body.appendChild(link);
      link.click();
      link.remove();
      URL.revokeObjectURL(url);
    } catch {
      setError("Failed to download shared collection.");
    }
  }

  function renderTree(parentId: string | null, depth: number): ReactElement {
    if (!payload) {
      return <></>;
    }

    const folders = payload.folders
      .filter((folder) => folder.parentId === parentId)
      .sort((a, b) => a.name.localeCompare(b.name));
    const requests = payload.requests
      .filter((request) => request.folderId === parentId)
      .sort((a, b) => a.name.localeCompare(b.name));

    return (
      <>
        {folders.map((folder) => {
          const hasChildren = payload.folders.some((item) => item.parentId === folder.id) || payload.requests.some((item) => item.folderId === folder.id);
          const isOpen = expandedFolders.has(folder.id);
          const isSelected = selected.type === "folder" && selected.folderId === folder.id;

          return (
            <div key={folder.id}>
              <div
                className="pm-tree-item"
                style={{ paddingLeft: 8 + depth * 16, background: isSelected ? "var(--surface-active)" : undefined }}
                onClick={() => {
                  setSelected({ type: "folder", folderId: folder.id });
                  setGroupTab("overview");
                }}
              >
                <button
                  className="pm-btn-icon"
                  style={{ width: 16, height: 16, marginRight: 4 }}
                  onClick={(event) => {
                    event.stopPropagation();
                    if (hasChildren) {
                      toggleFolder(folder.id);
                    }
                  }}
                >
                  {hasChildren ? (isOpen ? "▼" : "▶") : ""}
                </button>
                <span className="pm-tree-label">{folder.name}</span>
              </div>
              {isOpen ? renderTree(folder.id, depth + 1) : null}
            </div>
          );
        })}

        {requests.map((request) => {
          const isSelected = selected.type === "request" && selected.requestId === request.id;
          return (
            <div
              key={request.id}
              className="pm-tree-item"
              style={{ paddingLeft: 24 + depth * 16, background: isSelected ? "var(--surface-active)" : undefined }}
              onClick={() => {
                setSelected({ type: "request", requestId: request.id });
                setRequestTab("overview");
              }}
            >
              <span className={`pm-method pm-method-${request.method}`} style={{ fontSize: 9 }}>
                {request.method}
              </span>
              <span className="pm-tree-label">{request.name}</span>
            </div>
          );
        })}
      </>
    );
  }

  const queries = selectedRequest ? parseQueryParams(selectedRequest.url ?? "") : [];
  const requestHeaders = (selectedRequest?.headers ?? []).filter((item) => item.enabled !== false && item.key);
  const requestAuth = normalizeAuth(selectedRequest?.auth);

  return (
    <main style={{ minHeight: "100vh", background: "var(--bg)", color: "var(--text)", display: "flex", flexDirection: "column" }}>
      <header style={{ borderBottom: "1px solid var(--border)", background: "var(--bg-elevated)", padding: "12px 16px", display: "flex", justifyContent: "space-between", alignItems: "center", gap: 8 }}>
        <div style={{ fontWeight: 700, fontSize: 14 }}>Shared Collection</div>
        <div style={{ display: "flex", gap: 8 }}>
          <button className="pm-btn pm-btn-primary" onClick={() => void handleDownload()}>
            Download JSON
          </button>
          <Link href="/login" className="pm-btn pm-btn-secondary" style={{ textDecoration: "none" }}>
            Open App
          </Link>
        </div>
      </header>

      <div style={{ display: "flex", flex: 1, minHeight: 0 }}>
        <aside style={{ width: 330, borderRight: "1px solid var(--border)", background: "var(--bg-elevated)", overflow: "auto" }}>
          <div
            className="pm-tree-item"
            style={{ borderBottom: "1px solid var(--border)", background: selected.type === "collection" ? "var(--surface-active)" : undefined }}
            onClick={() => {
              setSelected({ type: "collection" });
              setGroupTab("overview");
            }}
          >
            <span className="pm-tree-label" style={{ fontWeight: 700 }}>{payload?.collection.name ?? "Collection"}</span>
          </div>
          <div style={{ paddingTop: 6 }}>
            {!loading && !error && payload ? renderTree(null, 1) : null}
          </div>
        </aside>

        <section style={{ flex: 1, display: "flex", flexDirection: "column", minWidth: 0 }}>
          {loading ? (
            <div className="pm-empty" style={{ flex: 1 }}><p>Loading shared collection...</p></div>
          ) : error ? (
            <div className="pm-empty" style={{ flex: 1 }}><p>{error}</p></div>
          ) : payload ? (
            <>
              {selected.type === "request" && selectedRequest ? (
                <>
                  <div style={{ padding: "10px 14px", borderBottom: "1px solid var(--border)", fontWeight: 700 }}>
                    {selectedRequest.name}
                  </div>
                  <div className="pm-editor-tabs">
                    <div style={{ display: "flex", flex: 1 }}>
                      {(["overview", "authorization", "headers", "body"] as RequestTab[]).map((tab) => (
                        <button
                          key={tab}
                          className={`pm-editor-tab ${requestTab === tab ? "pm-editor-tab-active" : ""}`}
                          onClick={() => setRequestTab(tab)}
                        >
                          {tab === "overview" ? "Overview" : tab === "authorization" ? "Authorization" : tab === "headers" ? "Headers" : "Body"}
                        </button>
                      ))}
                    </div>
                  </div>
                  <div style={{ padding: 12, overflow: "auto", flex: 1 }}>
                    {requestTab === "overview" && (
                      <>
                        <div style={{ marginBottom: 10 }}>
                          <span className={`pm-method pm-method-${selectedRequest.method}`}>{selectedRequest.method}</span>
                          <span style={{ marginLeft: 8, fontFamily: "var(--font-mono)", fontSize: 12, color: "var(--text-secondary)" }}>{selectedRequest.url}</span>
                        </div>
                        {queries.length > 0 ? (
                          <table className="pm-kv-table">
                            <thead><tr><th>Query Key</th><th>Value</th><th /></tr></thead>
                            <tbody>
                              {queries.map((item, index) => (
                                <tr key={`${item.key}_${index}`}>
                                  <td><input type="text" readOnly value={item.key} /></td>
                                  <td><input type="text" readOnly value={item.value} /></td>
                                  <td />
                                </tr>
                              ))}
                            </tbody>
                          </table>
                        ) : (
                          <p style={{ color: "var(--muted)", fontSize: 12 }}>No query parameters.</p>
                        )}
                      </>
                    )}

                    {requestTab === "authorization" && (
                      <div style={{ border: "1px solid var(--border)", borderRadius: 8, padding: 12, background: "var(--surface)" }}>
                        <p style={{ margin: 0, fontSize: 12 }}>
                          <strong>Type:</strong> {requestAuth.type === "api-key" ? "API Key" : requestAuth.type}
                        </p>
                        {requestAuth.type === "basic" ? (
                          <p style={{ marginTop: 8, fontSize: 12, color: "var(--text-secondary)" }}>
                            Username: {requestAuth.basic.username || "(empty)"}
                          </p>
                        ) : null}
                        {requestAuth.type === "bearer" ? (
                          <p style={{ marginTop: 8, fontSize: 12, color: "var(--text-secondary)" }}>
                            Bearer token configured
                          </p>
                        ) : null}
                        {requestAuth.type === "api-key" ? (
                          <p style={{ marginTop: 8, fontSize: 12, color: "var(--text-secondary)" }}>
                            API key location: {requestAuth.apiKey.addTo}
                          </p>
                        ) : null}
                      </div>
                    )}

                    {requestTab === "headers" && (
                      requestHeaders.length > 0 ? (
                        <table className="pm-kv-table">
                          <thead><tr><th>Header</th><th>Value</th><th /></tr></thead>
                          <tbody>
                            {requestHeaders.map((item, index) => (
                              <tr key={`${item.key}_${index}`}>
                                <td><input type="text" readOnly value={item.key} /></td>
                                <td><input type="text" readOnly value={item.value} /></td>
                                <td />
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      ) : (
                        <p style={{ color: "var(--muted)", fontSize: 12 }}>No headers.</p>
                      )
                    )}

                    {requestTab === "body" && (
                      <textarea className="pm-input" readOnly value={selectedRequest.bodyRaw ?? selectedRequest.body ?? ""} style={{ minHeight: 220, width: "100%" }} />
                    )}
                  </div>
                </>
              ) : (
                <>
                  <div style={{ padding: "10px 14px", borderBottom: "1px solid var(--border)", fontWeight: 700 }}>
                    {selected.type === "folder" ? selectedFolder?.name ?? "Folder" : payload.collection.name}
                  </div>
                  <div className="pm-editor-tabs">
                    <div style={{ display: "flex", flex: 1 }}>
                      {(["overview", "authorization", "variables"] as GroupTab[]).map((tab) => (
                        <button
                          key={tab}
                          className={`pm-editor-tab ${groupTab === tab ? "pm-editor-tab-active" : ""}`}
                          onClick={() => setGroupTab(tab)}
                        >
                          {tab === "overview" ? "Overview" : tab === "authorization" ? "Authorization" : "Variables"}
                        </button>
                      ))}
                    </div>
                  </div>
                  <div style={{ padding: 12, overflow: "auto", flex: 1 }}>
                    {groupTab === "overview" && (
                      <>
                        <h2 style={{ marginTop: 0 }}>{selected.type === "folder" ? selectedFolder?.name : payload.collection.name}</h2>
                        <p style={{ color: "var(--text-secondary)", fontSize: 13 }}>
                          {(selected.type === "folder" ? selectedFolder?.description : payload.collection.description) || "No description provided."}
                        </p>
                        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginTop: 10 }}>
                          <span className="pm-badge pm-badge-info">Requests: {payload.requests.length}</span>
                          <span className="pm-badge pm-badge-neutral">Folders: {payload.folders.length}</span>
                          <span className="pm-badge pm-badge-neutral">Exported: {new Date(payload.exportedAt).toLocaleString()}</span>
                        </div>
                      </>
                    )}

                    {groupTab === "authorization" && (
                      <div style={{ border: "1px solid var(--border)", borderRadius: 8, padding: 12, background: "var(--surface)" }}>
                        <p style={{ margin: 0, fontSize: 12 }}>
                          Collection/folder authorization settings are represented in layout form here. Scripts and Runs are intentionally omitted.
                        </p>
                      </div>
                    )}

                    {groupTab === "variables" && (
                      <div style={{ border: "1px solid var(--border)", borderRadius: 8, padding: 12, background: "var(--surface)" }}>
                        <p style={{ margin: 0, fontSize: 12, color: "var(--text-secondary)" }}>
                          Environment variables are managed inside the app workspace and are not exposed in public shared links for security.
                        </p>
                      </div>
                    )}
                  </div>
                </>
              )}
            </>
          ) : null}
        </section>
      </div>
    </main>
  );
}

