export default function SharedCollectionPage({
  params,
}: {
  params: Promise<{ slug: string }>;
}): ReactElement {
  const { slug } = use(params);

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [payload, setPayload] = useState<SharedPayload | null>(null);
  const [selectedItem, setSelectedItem] = useState<SelectedItem>({
    type: "collection",
  });
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set());

  useEffect(() => {
    let mounted = true;

    async function loadSharedCollection() {
      setLoading(true);
      setError(null);

      try {
        const response = await fetch(`/api/share/${slug}`, { cache: "no-store" });
        const body = (await response.json().catch(() => null)) as
          | { data?: SharedPayload; error?: string }
          | null;

        if (!response.ok || !body?.data) {
          throw new Error(body?.error || "Shared collection not found.");
        }

        if (mounted) {
          setPayload(body.data);
        }
      } catch (loadError) {
        const message =
          loadError instanceof Error
            ? loadError.message
            : "Unable to load shared collection.";
        if (mounted) {
          setPayload(null);
          setError(message);
        }
      } finally {
        if (mounted) {
          setLoading(false);
        }
      }
    }

    void loadSharedCollection();

    return () => {
      mounted = false;
    };
  }, [slug]);

  const handleToggleFolder = (folderId: string) => {
    const newExpanded = new Set(expandedFolders);
    if (newExpanded.has(folderId)) {
      newExpanded.delete(folderId);
    } else {
      newExpanded.add(folderId);
    }
    setExpandedFolders(newExpanded);
  };

  const handleDownload = async () => {
    if (!payload) return;
    try {
      const postmanCollection = buildPostmanCollection(payload);
      const blob = new Blob([JSON.stringify(postmanCollection, null, 2)], {
        type: "application/json",
      });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = `${payload.collection.name || "shared-collection"}.postman_collection.json`;
      document.body.appendChild(link);
      link.click();
      link.remove();
      URL.revokeObjectURL(url);
    } catch {
      setError("Failed to download shared collection.");
    }
  };

  const currentFolder =
    selectedItem.type === "folder"
      ? payload?.folders.find((f) => f.id === selectedItem.folderId)
      : undefined;

  const currentRequest =
    selectedItem.type === "request"
      ? payload?.requests.find((r) => r.id === selectedItem.requestId)
      : undefined;

  return (
    <main
      style={{
        minHeight: "100vh",
        background: "var(--bg)",
        color: "var(--text)",
        display: "flex",
        flexDirection: "column",
      }}
    >
      {/* Top Bar */}
      <header
        style={{
          borderBottom: "1px solid var(--border)",
          padding: "12px 20px",
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          gap: 12,
          background: "var(--bg-elevated)",
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
            <path
              d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          </svg>
          <span style={{ fontWeight: 600, fontSize: 14 }}>Octoman</span>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <button
            className="pm-btn pm-btn-primary"
            onClick={() => void handleDownload()}
          >
            Download JSON
          </button>
          <Link
            href="/login"
            className="pm-btn pm-btn-secondary"
            style={{ textDecoration: "none" }}
          >
            Open App
          </Link>
        </div>
      </header>

      {/* Main Content */}
      <div style={{ display: "flex", flex: 1, overflow: "hidden" }}>
        {/* Sidebar */}
        <aside
          style={{
            width: 260,
            borderRight: "1px solid var(--border)",
            overflow: "auto",
            background: "var(--bg-elevated)",
            display: "flex",
            flexDirection: "column",
          }}
        >
          <div style={{ padding: 16, borderBottom: "1px solid var(--border)" }}>
            <div
              onClick={() => setSelectedItem({ type: "collection" })}
              style={{
                display: "flex",
                alignItems: "center",
                gap: 8,
                padding: "8px 10px",
                borderRadius: 4,
                cursor: "pointer",
                background:
                  selectedItem.type === "collection"
                    ? "rgba(73, 204, 144, 0.1)"
                    : "transparent",
                borderLeft:
                  selectedItem.type === "collection"
                    ? "3px solid #49cc90"
                    : "3px solid transparent",
                fontSize: 12,
                fontWeight: selectedItem.type === "collection" ? 600 : 400,
                color:
                  selectedItem.type === "collection"
                    ? "var(--text)"
                    : "var(--text-secondary)",
                transition: "all 0.15s",
                userSelect: "none",
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.background =
                  selectedItem.type === "collection"
                    ? "rgba(73, 204, 144, 0.15)"
                    : "rgba(255, 255, 255, 0.05)";
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.background =
                  selectedItem.type === "collection"
                    ? "rgba(73, 204, 144, 0.1)"
                    : "transparent";
              }}
            >
              <span style={{ fontSize: 14 }}>📦</span>
