"use client";

import { useRef, useEffect, type ReactElement } from "react";
import { EditorView, keymap, placeholder as phExtension } from "@codemirror/view";
import { EditorState, type Extension } from "@codemirror/state";
import { defaultKeymap, history, historyKeymap } from "@codemirror/commands";
import { json } from "@codemirror/lang-json";
import { xml } from "@codemirror/lang-xml";
import { javascript } from "@codemirror/lang-javascript";
import { html } from "@codemirror/lang-html";
import { css } from "@codemirror/lang-css";
import { bracketMatching, foldGutter, syntaxHighlighting, defaultHighlightStyle } from "@codemirror/language";
import { searchKeymap, highlightSelectionMatches } from "@codemirror/search";
import { autocompletion, closeBrackets, closeBracketsKeymap } from "@codemirror/autocomplete";
import { lintGutter } from "@codemirror/lint";

export type CodeLanguage = "json" | "xml" | "html" | "javascript" | "css" | "text" | "graphql";

const langExtensions: Record<string, () => Extension> = {
  json: () => json(),
  xml: () => xml(),
  javascript: () => javascript(),
  html: () => html(),
  css: () => css(),
  graphql: () => javascript(), // graphql uses JS-like syntax highlighting
  text: () => [],
};

interface CodeEditorProps {
  value: string;
  onChange?: (value: string) => void;
  language?: CodeLanguage;
  readOnly?: boolean;
  placeholder?: string;
  className?: string;
  style?: React.CSSProperties;
  minHeight?: string;
}

export function CodeEditor({
  value,
  onChange,
  language = "json",
  readOnly = false,
  placeholder = "",
  className = "",
  style,
  minHeight = "120px",
}: CodeEditorProps): ReactElement {
  const containerRef = useRef<HTMLDivElement>(null);
  const viewRef = useRef<EditorView | null>(null);
  const onChangeRef = useRef(onChange);
  onChangeRef.current = onChange;

  // Create editor once
  useEffect(() => {
    if (!containerRef.current) return;

    const langExt = langExtensions[language]?.() ?? [];

    const extensions: Extension[] = [
      keymap.of([...defaultKeymap, ...historyKeymap, ...closeBracketsKeymap, ...searchKeymap]),
      history(),
      bracketMatching(),
      closeBrackets(),
      foldGutter(),
      autocompletion(),
      highlightSelectionMatches(),
      syntaxHighlighting(defaultHighlightStyle, { fallback: true }),
      lintGutter(),
      langExt,
      EditorView.lineWrapping,
      EditorView.theme({
        "&": { minHeight, backgroundColor: "var(--bg-elevated)" },
        ".cm-content": { fontFamily: "var(--font-mono)", padding: "8px 0" },
        ".cm-line": { padding: "0 8px" },
      }),
      EditorView.updateListener.of((update) => {
        if (update.docChanged && onChangeRef.current) {
          onChangeRef.current(update.state.doc.toString());
        }
      }),
    ];

    if (placeholder) {
      extensions.push(phExtension(placeholder));
    }

    if (readOnly) {
      extensions.push(EditorState.readOnly.of(true));
    }

    const state = EditorState.create({
      doc: value,
      extensions,
    });

    const view = new EditorView({
      state,
      parent: containerRef.current,
    });

    viewRef.current = view;

    return () => {
      view.destroy();
      viewRef.current = null;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [language, readOnly]);

  // Sync external value changes
  useEffect(() => {
    const view = viewRef.current;
    if (!view) return;
    const current = view.state.doc.toString();
    if (current !== value) {
      view.dispatch({
        changes: { from: 0, to: current.length, insert: value },
      });
    }
  }, [value]);

  return <div ref={containerRef} className={`cm-editor-wrapper ${className}`} style={style} />;
}

"use client";

import type { ReactElement } from "react";
import { useCallback, useMemo, useState } from "react";
import { useWorkspaceStore, createDefaultBuilder } from "@/stores/workspace-store";
import { useToast } from "@/hooks/useToast";
import type { CollectionDto, DocumentationFolderDto, RequestDto, HttpMethod } from "@/types";

function toPostmanAuth(auth: RequestDto["auth"]):
  | { type: "noauth" }
  | { type: "basic"; basic: { key: string; value: string; type: string }[] }
  | { type: "bearer"; bearer: { key: string; value: string; type: string }[] }
  | { type: "apikey"; apikey: { key: string; value: string; type: string }[] } {
  if (auth.type === "basic") {
    return {
      type: "basic",
      basic: [
        { key: "username", value: auth.basic.username, type: "string" },
        { key: "password", value: auth.basic.password, type: "string" },
      ],
    };
  }

  if (auth.type === "bearer") {
    return {
      type: "bearer",
      bearer: [{ key: "token", value: auth.bearerToken, type: "string" }],
    };
  }

  if (auth.type === "api-key") {
    return {
      type: "apikey",
      apikey: [
        { key: "key", value: auth.apiKey.key, type: "string" },
        { key: "value", value: auth.apiKey.value, type: "string" },
        { key: "in", value: auth.apiKey.addTo === "query" ? "query" : "header", type: "string" },
      ],
    };
  }

  return { type: "noauth" };
}

function toPostmanBody(request: RequestDto):
  | { mode: "raw"; raw: string }
  | { mode: "formdata"; formdata: { key: string; value: string; disabled?: boolean; type: "text" }[] }
  | { mode: "urlencoded"; urlencoded: { key: string; value: string; disabled?: boolean }[] }
  | undefined {
  if (request.body_mode === "raw") {
    return {
      mode: "raw",
      raw: request.body_raw ?? request.body ?? "",
    };
  }

  if (request.body_mode === "form-data") {
    return {
      mode: "formdata",
      formdata: (request.body_form ?? [])
        .filter((item) => Boolean(item.key))
        .map((item) => ({
          key: item.key,
          value: item.value,
          disabled: item.enabled === false ? true : undefined,
          type: "text",
        })),
    };
  }

  if (request.body_mode === "x-www-form-urlencoded") {
    return {
      mode: "urlencoded",
      urlencoded: (request.body_form ?? [])
        .filter((item) => Boolean(item.key))
        .map((item) => ({
          key: item.key,
          value: item.value,
          disabled: item.enabled === false ? true : undefined,
        })),
    };
  }

  return undefined;
}

// ---------------------------------------------------------------------------
// Postman v2.1 URL builder — handles standard URLs, env-var URLs, and
// separately-stored query_params from the request model.
// ---------------------------------------------------------------------------

function buildPostmanUrlObject(request: RequestDto): Record<string, unknown> {
  const rawUrl = request.url?.trim() || "";

  // Merge extra query_params stored separately in the request model.
  // These may not be embedded in the url string when the user edits them
  // via the Params editor.
  const extraParams = ((request.query_params ?? []) as { key: string; value: string; enabled?: boolean }[])
    .filter((p) => Boolean(p.key))
    .map((p) => ({
      key: p.key,
      value: p.value ?? "",
      ...(p.enabled === false ? { disabled: true } : {}),
    }));

  // ── Case 1: env-variable URL like {{BASE_URL}}/path?q=1
  const envMatch = rawUrl.match(/^(\{\{[^}]+\}\})(\/[^?#]*)?([?#].*)?$/);
  if (envMatch) {
    const hostVar = envMatch[1];
    const pathStr = envMatch[2] ?? "";
    const queryStr = envMatch[3] ?? "";

    const path = pathStr.replace(/^\//, "").split("/").filter(Boolean);
    const inlineQuery = queryStr.startsWith("?")
      ? queryStr.slice(1).split("&").filter(Boolean).map((p) => {
          const eqIdx = p.indexOf("=");
          return eqIdx === -1 ? { key: p, value: "" } : { key: p.slice(0, eqIdx), value: p.slice(eqIdx + 1) };
        })
      : [];
    const query = [...inlineQuery, ...extraParams];

    return {
      raw: rawUrl,
      host: [hostVar],
      ...(path.length > 0 ? { path } : {}),
      ...(query.length > 0 ? { query } : {}),
    };
  }

  // ── Case 2: standard parseable URL
  try {
    const u = new URL(rawUrl);
    const path = u.pathname.replace(/^\//, "").split("/").filter(Boolean);
    const inlineQuery: { key: string; value: string }[] = [];
    u.searchParams.forEach((value, key) => inlineQuery.push({ key, value }));
    const query = [...inlineQuery, ...extraParams];

    // Rebuild raw with all query params so raw is the canonical string
    let finalRaw = rawUrl;
    if (extraParams.length > 0) {
      const qs = [...u.searchParams.entries(), ...extraParams.map((p) => [p.key, p.value] as [string, string])];
      u.search = new URLSearchParams(qs).toString();
      finalRaw = u.toString();
    }

    return {
      raw: finalRaw,
      protocol: u.protocol.replace(":", ""),
      host: u.hostname.split("."),
      ...(u.port ? { port: u.port } : {}),
      ...(path.length > 0 ? { path } : {}),
      ...(query.length > 0 ? { query } : {}),
    };
  } catch {
    // ── Case 3: unparseable (e.g. relative path, malformed)
    return { raw: rawUrl || "https://example.com", host: [rawUrl || "https://example.com"] };
  }
}

function toPostmanRequestItem(request: RequestDto): {
  name: string;
  request: {
    method: HttpMethod;
    header: { key: string; value: string; disabled?: boolean }[];
    body?:
      | { mode: "raw"; raw: string }
      | { mode: "formdata"; formdata: { key: string; value: string; disabled?: boolean; type: "text" }[] }
      | { mode: "urlencoded"; urlencoded: { key: string; value: string; disabled?: boolean }[] };
    url: Record<string, unknown>;
    auth:
      | { type: "noauth" }
      | { type: "basic"; basic: { key: string; value: string; type: string }[] }
      | { type: "bearer"; bearer: { key: string; value: string; type: string }[] }
      | { type: "apikey"; apikey: { key: string; value: string; type: string }[] };
    description?: string;
  };
  response: [];
} {
  const body = toPostmanBody(request);
  return {
    name: request.name || "Untitled",
    request: {
      method: request.method,
      header: (request.headers ?? [])
        .filter((item) => Boolean(item.key))
        .map((item) => ({
          key: item.key,
          value: item.value,
          disabled: item.enabled === false ? true : undefined,
        })),
      ...(body ? { body } : {}),
      url: buildPostmanUrlObject(request),
      auth: toPostmanAuth(request.auth),
      ...(request.description ? { description: request.description } : {}),
    },
    response: [],
  };
}

/* ------------------------------------------------------------------ */
/*  Icon helpers                                                       */
/* ------------------------------------------------------------------ */

function ChevronIcon({ open }: { open: boolean }): ReactElement {
  return (
    <svg
      className="pm-tree-chevron"
      viewBox="0 0 16 16"
      style={{ transform: open ? "rotate(90deg)" : "none", transition: "transform 150ms" }}
    >
      <path d="M6 4l4 4-4 4" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
    </svg>
  );
}

function FolderIcon(): ReactElement {
  return (
    <svg className="pm-tree-icon" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.2">
      <path d="M2 4h4l1.5 1.5H14v7H2V4z" />
    </svg>
  );
}

function MethodBadge({ method }: { method: HttpMethod }): ReactElement {
  return <span className={`pm-method pm-method-${method}`}>{method}</span>;
}

/* ------------------------------------------------------------------ */
/*  Main tree                                                          */
/* ------------------------------------------------------------------ */

export function CollectionTree(): ReactElement {
  const collections = useWorkspaceStore((s) => s.collections);
  const requests = useWorkspaceStore((s) => s.requests);
  const folders = useWorkspaceStore((s) => s.folders);
  const environments = useWorkspaceStore((s) => s.environments);
  const treeSearch = useWorkspaceStore((s) => s.treeSearch);
  const expanded = useWorkspaceStore((s) => s.expandedCollectionIds);
  const folderExpanded = useWorkspaceStore((s) => s.expandedFolderIds);
  const toggleCollection = useWorkspaceStore((s) => s.toggleCollection);
  const toggleFolder = useWorkspaceStore((s) => s.toggleFolder);
  const openTab = useWorkspaceStore((s) => s.openTab);
  const { toast } = useToast();
  const [contextMenu, setContextMenu] = useState<{ x: number; y: number; type: string; id: string; collectionId?: string; folderId?: string } | null>(null);

  const safeCollections = useMemo(
    () =>
      (Array.isArray(collections) ? collections : []).filter(
        (item): item is CollectionDto =>
          Boolean(item && typeof item.id === "string" && item.id && typeof item.name === "string"),
      ),
    [collections],
  );

  const safeRequests = useMemo(
    () =>
      (Array.isArray(requests) ? requests : []).filter(
        (item): item is RequestDto => Boolean(item && typeof item.id === "string" && item.id),
      ),
    [requests],
  );

  const safeFolders = useMemo(
    () =>
      (Array.isArray(folders) ? folders : []).filter(
        (item): item is DocumentationFolderDto =>
          Boolean(item && typeof item.id === "string" && item.id && typeof item.name === "string"),
      ),
    [folders],
  );

  const sortedCollections = useMemo(
    () => [...safeCollections].sort((a, b) => a.sort_order - b.sort_order || a.name.localeCompare(b.name)),
    [safeCollections],
  );

  const filterLower = (treeSearch ?? "").toLowerCase();

  const openRequest = useCallback(
    (req: RequestDto) => {
      const builder = createDefaultBuilder(req.collection_id, req.folder_id);
      builder.id = req.id;
      builder.name = req.name ?? "";
      builder.description = req.description ?? "";
      builder.request_type = req.request_type ?? "http";
      builder.method = req.method;
      builder.url = req.url ?? "";
      builder.query_params = req.query_params ?? [];
      builder.headers = req.headers ?? [];
      builder.bodyMode = req.body_mode ?? "raw";
      builder.bodyRawLanguage = req.body_raw_language ?? "json";
      builder.bodyRaw = req.body_raw ?? "";
      builder.bodyForm = req.body_form ?? [];
      builder.auth = req.auth;
      builder.preRequestScript = req.pre_request_script ?? "";
      builder.testScript = req.test_script ?? "";
      builder.graphqlQuery = req.graphql_query ?? "";
      builder.graphqlVariables = req.graphql_variables ?? "";
      builder.sort_order = req.sort_order ?? 0;
      builder._dirty = false;
      openTab(req.id, builder);
    },
    [openTab],
  );

  const handleNewRequest = useCallback(
    async (collectionId: string, folderId: string | null = null) => {
      try {
        const res = await fetch("/api/requests", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            collectionId,
            folderId,
            name: "New Request",
            method: "GET",
            url: "https://api.example.com",
          }),
        });
        if (!res.ok) throw new Error("Failed to create request");
        const payload = (await res.json().catch(() => null)) as { data?: RequestDto } | null;
        const newReq = payload?.data;
        if (!newReq?.id) throw new Error("Invalid response payload");
        const store = useWorkspaceStore.getState();
        store.setRequests([...(Array.isArray(store.requests) ? store.requests : []), newReq]);
        openRequest(newReq);
        toast("success", "Request created");
      } catch {
        toast("error", "Failed to create request");
      }
    },
    [openRequest, toast],
  );

  const handleNewCollection = useCallback(async () => {
    try {
      const res = await fetch("/api/collections", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: "New Collection" }),
      });
      if (!res.ok) throw new Error("Failed");
      const payload = (await res.json().catch(() => null)) as { data?: CollectionDto } | null;
      const collection = payload?.data;
      if (!collection?.id) throw new Error("Invalid response payload");
      const store = useWorkspaceStore.getState();
      store.setCollections([...(Array.isArray(store.collections) ? store.collections : []), collection]);
      toast("success", "Collection created");
    } catch {
      toast("error", "Failed to create collection");
    }
  }, [toast]);

  const handleNewFolder = useCallback(
    async (collectionId: string, parentId: string | null = null) => {
      try {
        const store = useWorkspaceStore.getState();
        const existingFolders = Array.isArray(store.folders) ? store.folders : [];
        const siblingNames = new Set(
          existingFolders
            .filter(
              (f) =>
                f.collection_id === collectionId &&
                (f.parent_id ?? null) === (parentId ?? null),
            )
            .map((f) => f.name.toLowerCase()),
        );

        let folderName = "New Folder";
        let suffix = 2;
        while (siblingNames.has(folderName.toLowerCase())) {
          folderName = `New Folder ${suffix}`;
          suffix += 1;
        }

        const body: Record<string, unknown> = {
          name: folderName,
          collectionId,
        };
        if (parentId) body.parentId = parentId;
        const res = await fetch("/api/documentation/folders", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(body),
        });
        if (!res.ok) throw new Error("Failed");
        const payload = (await res.json().catch(() => null)) as { data?: DocumentationFolderDto } | null;
        const folder = payload?.data;
        if (!folder?.id) throw new Error("Invalid response payload");
        store.setFolders([...(Array.isArray(store.folders) ? store.folders : []), folder]);
        toast("success", "Folder created");
      } catch {
        toast("error", "Failed to create folder");
      }
    },
    [toast],
  );

  function renderFolder(folder: DocumentationFolderDto | null | undefined, depth: number, collectionId: string): ReactElement {
    if (!folder?.id) {
      return <></>;
    }

    const isOpen = !!folderExpanded[folder.id];
    const folderCollectionId = folder.collection_id ?? collectionId;
    const childFolders = safeFolders
      .filter(
        (f) =>
          f.parent_id === folder.id &&
          (f.collection_id ?? folderCollectionId) === folderCollectionId,
      )
      .sort((a, b) => a.sort_order - b.sort_order || a.name.localeCompare(b.name));
    const childRequests = safeRequests
      .filter((r) => r.folder_id === folder.id)
      .sort((a, b) => (a.sort_order ?? 0) - (b.sort_order ?? 0) || a.name.localeCompare(b.name));

    if (
      filterLower &&
      !folder.name.toLowerCase().includes(filterLower) &&
      childFolders.every((f) => !f.name.toLowerCase().includes(filterLower)) &&
      childRequests.every((r) => !(r.name ?? "").toLowerCase().includes(filterLower))
    ) {
      return <></>;
    }

    return (
      <div key={folder.id}>
        <div
          className="pm-tree-item"
          style={{ paddingLeft: 8 + depth * 16 }}
          onClick={() => toggleFolder(folder.id)}
          onContextMenu={(e) => {
            e.preventDefault();
            setContextMenu({ x: e.clientX, y: e.clientY, type: "folder", id: folder.id, collectionId });
          }}
        >
          <ChevronIcon open={isOpen} />
          <FolderIcon />
          <span className="pm-tree-label">{folder.name}</span>
          <div className="pm-tree-actions">
            <button className="pm-btn-icon" title="Add request" onClick={(e) => { e.stopPropagation(); handleNewRequest(collectionId, folder.id); }}>
              <span style={{ fontSize: 14 }}>+</span>
            </button>
            <button className="pm-btn-icon" title="Add subfolder" onClick={(e) => { e.stopPropagation(); handleNewFolder(collectionId, folder.id); }}>
              <span style={{ fontSize: 12 }}>📁</span>
            </button>
          </div>
        </div>
        {isOpen && (
          <>
            {childFolders.map((cf) => renderFolder(cf, depth + 1, collectionId))}
            {childRequests.map((req) => (
              <div
                key={req.id}
                className="pm-tree-item"
                style={{ paddingLeft: 8 + (depth + 1) * 16 }}
                onClick={() => openRequest(req)}
                onContextMenu={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  setContextMenu({ x: e.clientX, y: e.clientY, type: "request", id: req.id, collectionId, folderId: folder.id });
                }}
              >
                <MethodBadge method={req.method} />
                <span className="pm-tree-label">{req.name || "Untitled"}</span>
                <div className="pm-tree-actions">
                  <button className="pm-btn-icon" title="Delete request" onClick={(e) => { e.stopPropagation(); handleDeleteRequest(req.id); }} style={{ color: "var(--error)" }}>
                    <span style={{ fontSize: 12 }}>×</span>
                  </button>
                </div>
              </div>
            ))}
          </>
        )}
      </div>
    );
  }

  function renderCollection(col: CollectionDto | null | undefined): ReactElement {
    if (!col?.id) {
      return <></>;
    }

    const isOpen = !!expanded[col.id];
    // Legacy fallback: older folders may not have collection_id populated yet.
    const legacyFolderIds = new Set(
      safeRequests
        .filter((r) => r.collection_id === col.id && r.folder_id)
        .map((r) => r.folder_id as string),
    );

    let changed = true;
    while (changed) {
      changed = false;
      safeFolders.forEach((f) => {
        if (legacyFolderIds.has(f.id) && f.parent_id && !legacyFolderIds.has(f.parent_id)) {
          legacyFolderIds.add(f.parent_id);
          changed = true;
        }
      });
    }

    const topFolders = safeFolders
      .filter(
        (f) =>
          !f.parent_id &&
          (f.collection_id === col.id || (!f.collection_id && legacyFolderIds.has(f.id))),
      )
      .sort((a, b) => a.sort_order - b.sort_order || a.name.localeCompare(b.name));
    const topRequests = safeRequests
      .filter((r) => r.collection_id === col.id && !r.folder_id)
      .sort((a, b) => (a.sort_order ?? 0) - (b.sort_order ?? 0) || a.name.localeCompare(b.name));

    if (filterLower && !col.name.toLowerCase().includes(filterLower) && topRequests.every((r) => !(r.name ?? "").toLowerCase().includes(filterLower))) {
      return <></>;
    }

    return (
      <div key={col.id}>
        <div
          className="pm-tree-item"
          onClick={() => toggleCollection(col.id)}
          onContextMenu={(e) => {
            e.preventDefault();
            setContextMenu({ x: e.clientX, y: e.clientY, type: "collection", id: col.id });
          }}
        >
          <ChevronIcon open={isOpen} />
          <span className="pm-tree-label" style={{ fontWeight: 600 }}>{col.name}</span>
          <div className="pm-tree-actions">
            <button className="pm-btn-icon" title="Add request" onClick={(e) => { e.stopPropagation(); handleNewRequest(col.id); }}>
              <span style={{ fontSize: 14 }}>+</span>
            </button>
            <button className="pm-btn-icon" title="Add folder" onClick={(e) => { e.stopPropagation(); handleNewFolder(col.id); }}>
              <span style={{ fontSize: 12 }}>📁</span>
            </button>
          </div>
        </div>
        {isOpen && (
          <>
            {topFolders.map((f) => renderFolder(f, 1, col.id))}
            {topRequests.map((req) => (
              <div
                key={req.id}
                className="pm-tree-item"
                style={{ paddingLeft: 24 }}
                onClick={() => openRequest(req)}
                onContextMenu={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  setContextMenu({ x: e.clientX, y: e.clientY, type: "request", id: req.id, collectionId: col.id });
                }}
              >
                <MethodBadge method={req.method} />
                <span className="pm-tree-label">{req.name || "Untitled"}</span>
                <div className="pm-tree-actions">
                  <button className="pm-btn-icon" title="Delete request" onClick={(e) => { e.stopPropagation(); handleDeleteRequest(req.id); }} style={{ color: "var(--error)" }}>
                    <span style={{ fontSize: 12 }}>×</span>
                  </button>
                </div>
              </div>
            ))}
          </>
        )}
      </div>
    );
  }

  return (
    <div style={{ padding: "4px 0" }}>
      {/* New collection button */}
      <div style={{ padding: "4px 8px 8px" }}>
        <button className="pm-btn pm-btn-secondary" style={{ width: "100%", height: 28, fontSize: 11 }} onClick={handleNewCollection}>
          + New Collection
        </button>
      </div>

      {sortedCollections.length === 0 ? (
        <div className="pm-empty" style={{ padding: "20px" }}>
          <p>No collections yet</p>
        </div>
      ) : (
        sortedCollections.map((c) => renderCollection(c))
      )}

      {/* Context menu */}
      {contextMenu && (
        <>
          <div style={{ position: "fixed", inset: 0, zIndex: 99 }} onClick={() => setContextMenu(null)} />
          <div className="pm-context-menu" style={{ position: "fixed", left: contextMenu.x, top: contextMenu.y, zIndex: 100 }}>
            {contextMenu.type === "collection" && (
              <>
                <button className="pm-context-item" onClick={() => { handleNewRequest(contextMenu.id); setContextMenu(null); }}>Add Request</button>
                <button className="pm-context-item" onClick={() => { handleNewFolder(contextMenu.id); setContextMenu(null); }}>Add Folder</button>
                <div className="pm-context-separator" />
                <button className="pm-context-item" onClick={() => { handleRenameCollection(contextMenu.id); setContextMenu(null); }}>Rename</button>
                <button className="pm-context-item" onClick={() => { handleDuplicateCollection(contextMenu.id); setContextMenu(null); }}>Duplicate</button>
                <div className="pm-context-separator" />
                <button className="pm-context-item" onClick={() => { handleSortCollection(contextMenu.id, "name"); setContextMenu(null); }}>Sort by Name</button>
                <button className="pm-context-item" onClick={() => { handleSetCollectionEnvironment(contextMenu.id); setContextMenu(null); }}>Set Environment</button>
                <button className="pm-context-item" onClick={() => { handleExportCollection(contextMenu.id); setContextMenu(null); }}>Export</button>
                <button className="pm-context-item" onClick={() => { handleShareCollection(contextMenu.id); setContextMenu(null); }}>Share</button>
                <div className="pm-context-separator" />
                <button className="pm-context-item pm-context-item-danger" onClick={() => { handleDeleteCollection(contextMenu.id); setContextMenu(null); }}>Delete</button>
              </>
            )}
            {contextMenu.type === "folder" && (
              <>
                <button className="pm-context-item" onClick={() => { handleNewRequest(contextMenu.collectionId ?? "", contextMenu.id); setContextMenu(null); }}>Add Request</button>
                <button className="pm-context-item" onClick={() => { handleNewFolder(contextMenu.collectionId ?? "", contextMenu.id); setContextMenu(null); }}>Add Subfolder</button>
                <div className="pm-context-separator" />
                <button className="pm-context-item" onClick={() => { handleRenameFolder(contextMenu.id); setContextMenu(null); }}>Rename</button>
                <div className="pm-context-separator" />
                <button className="pm-context-item pm-context-item-danger" onClick={() => { handleDeleteFolder(contextMenu.id); setContextMenu(null); }}>Delete Folder</button>
              </>
            )}
            {contextMenu.type === "request" && (
              <>
                <button className="pm-context-item" onClick={() => { handleDuplicateRequest(contextMenu.id); setContextMenu(null); }}>Duplicate</button>
                <button className="pm-context-item" onClick={() => { handleRenameRequest(contextMenu.id); setContextMenu(null); }}>Rename</button>
                <div className="pm-context-separator" />
                <button className="pm-context-item pm-context-item-danger" onClick={() => { handleDeleteRequest(contextMenu.id); setContextMenu(null); }}>Delete Request</button>
              </>
            )}
          </div>
        </>
      )}
    </div>
  );

  async function handleDeleteCollection(id: string) {
    try {
      const res = await fetch(`/api/collections/${id}`, { method: "DELETE" });
      if (!res.ok) throw new Error("Failed");
      const store = useWorkspaceStore.getState();
      const current = Array.isArray(store.collections) ? store.collections : [];
      store.setCollections(current.filter((c) => c.id !== id));
      toast("success", "Collection deleted");
    } catch {
      toast("error", "Failed to delete collection");
    }
  }

  async function handleDeleteFolder(id: string) {
    try {
      const res = await fetch(`/api/documentation/folders/${id}`, { method: "DELETE" });
      if (!res.ok) throw new Error("Failed");
      const store = useWorkspaceStore.getState();
      const current = Array.isArray(store.folders) ? store.folders : [];
      store.setFolders(current.filter((f) => f.id !== id));
      // Unlink requests that were in this folder
      const currentReqs = Array.isArray(store.requests) ? store.requests : [];
      store.setRequests(currentReqs.map((r) => r.folder_id === id ? { ...r, folder_id: null } : r));
      toast("success", "Folder deleted");
    } catch {
      toast("error", "Failed to delete folder");
    }
  }

  async function handleDeleteRequest(id: string) {
    try {
      const res = await fetch(`/api/requests/${id}`, { method: "DELETE" });
      if (!res.ok) throw new Error("Failed");
      const store = useWorkspaceStore.getState();
      const current = Array.isArray(store.requests) ? store.requests : [];
      store.setRequests(current.filter((r) => r.id !== id));
      toast("success", "Request deleted");
    } catch {
      toast("error", "Failed to delete request");
    }
  }

  async function handleRenameCollection(id: string) {
    const col = safeCollections.find((c) => c.id === id);
    if (!col) return;
    const newName = prompt("Rename collection:", col.name);
    if (!newName || newName === col.name) return;
    try {
      const res = await fetch(`/api/collections/${id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: newName }),
      });
      if (!res.ok) throw new Error("Failed");
      const { data } = await res.json();
      const store = useWorkspaceStore.getState();
      const current = Array.isArray(store.collections) ? store.collections : [];
      store.setCollections(current.map((c) => (c.id === id ? { ...c, ...data } : c)));
      toast("success", "Collection renamed");
    } catch {
      toast("error", "Failed to rename collection");
    }
  }

  async function handleDuplicateCollection(id: string) {
    const col = safeCollections.find((c) => c.id === id);
    if (!col) return;
    try {
      const res = await fetch("/api/collections", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: `${col.name} (Copy)` }),
      });
      if (!res.ok) throw new Error("Failed");
      const { data } = await res.json();
      if (!data?.id) throw new Error("Invalid response");
      const store = useWorkspaceStore.getState();
      store.setCollections([...(Array.isArray(store.collections) ? store.collections : []), data]);
      // Also duplicate all requests in this collection
      const colRequests = safeRequests.filter((r) => r.collection_id === id);
      for (const req of colRequests) {
        try {
          await fetch("/api/requests", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              collectionId: data.id,
              folderId: null,
              name: req.name,
              method: req.method,
              url: req.url,
            }),
          });
        } catch { /* ignore individual failures */ }
      }
      // Refresh requests
      try {
        const reqRes = await fetch("/api/requests?limit=250");
        if (reqRes.ok) {
          const reqJson = await reqRes.json();
          if (Array.isArray(reqJson.data)) store.setRequests(reqJson.data);
        }
      } catch { /* non-critical */ }
      toast("success", "Collection duplicated");
    } catch {
      toast("error", "Failed to duplicate collection");
    }
  }

  function handleSortCollection(id: string, by: "name") {
    const store = useWorkspaceStore.getState();
    const current = Array.isArray(store.requests) ? store.requests : [];
    const sorted = current.map((r) => {
      if (r.collection_id !== id) return r;
      return r;
    });
    // Sort by name and reassign sort_order locally
    const colReqs = sorted.filter((r) => r.collection_id === id).sort((a, b) => a.name.localeCompare(b.name));
    const others = sorted.filter((r) => r.collection_id !== id);
    store.setRequests([...others, ...colReqs.map((r, i) => ({ ...r, sort_order: i }))]);
    toast("success", "Sorted by name");
  }

  async function handleSetCollectionEnvironment(id: string) {
    const collection = safeCollections.find((item) => item.id === id);
    if (!collection) {
      return;
    }

    const safeEnvironments = (Array.isArray(environments) ? environments : []).filter(
      (item) => Boolean(item?.id && item?.name),
    );

    if (safeEnvironments.length === 0) {
      toast("warning", "Create an environment first");
      return;
    }

    const currentEnvironment = safeEnvironments.find(
      (item) => item.id === collection.environment_id,
    );

    const choices = safeEnvironments.map((item) => item.name).join(", ");
    const response = window.prompt(
      `Set environment for "${collection.name}".\nEnter environment name to bind. Leave blank to clear.\nAvailable: ${choices}`,
      currentEnvironment?.name ?? "",
    );

    if (response === null) {
      return;
    }

    const desiredName = response.trim();
    let environmentId: string | null = null;

    if (desiredName) {
      const match = safeEnvironments.find(
        (item) => item.name.toLowerCase() === desiredName.toLowerCase(),
      );

      if (!match) {
        toast("error", "Environment not found. Use an exact environment name.");
        return;
      }

      environmentId = match.id;
    }

    try {
      const res = await fetch(`/api/collections/${id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ environmentId }),
      });
      if (!res.ok) {
        throw new Error("Failed");
      }

      const payload = (await res.json().catch(() => null)) as { data?: CollectionDto } | null;
      const updated = payload?.data;
      if (!updated?.id) {
        throw new Error("Invalid response payload");
      }

      const store = useWorkspaceStore.getState();
      const current = Array.isArray(store.collections) ? store.collections : [];
      store.setCollections(current.map((item) => (item.id === id ? { ...item, ...updated } : item)));

      toast("success", environmentId ? "Collection environment set" : "Collection environment cleared");
    } catch {
      toast("error", "Failed to update collection environment");
    }
  }

  async function handleExportCollection(id: string) {
    try {
      const collection = safeCollections.find((item) => item.id === id);
      if (!collection) {
        throw new Error("Collection not found");
      }

      const collectionFolders = safeFolders
        .filter((item) => item.collection_id === id)
        .sort((a, b) => a.sort_order - b.sort_order || a.name.localeCompare(b.name));

      const collectionRequests = safeRequests
        .filter((item) => item.collection_id === id)
        .sort((a, b) => (a.sort_order ?? 0) - (b.sort_order ?? 0) || a.name.localeCompare(b.name));

      const foldersByParent = new Map<string, DocumentationFolderDto[]>();
      const requestsByFolder = new Map<string, RequestDto[]>();

      collectionFolders.forEach((folder) => {
        const key = folder.parent_id ?? "root";
        const list = foldersByParent.get(key) ?? [];
        list.push(folder);
        foldersByParent.set(key, list);
      });

      collectionRequests.forEach((requestItem) => {
        const key = requestItem.folder_id ?? "root";
        const list = requestsByFolder.get(key) ?? [];
        list.push(requestItem);
        requestsByFolder.set(key, list);
      });

      const buildItems = (parentId: string | null): unknown[] => {
        const key = parentId ?? "root";
        const childFolders = (foldersByParent.get(key) ?? []).map((folder) => ({
          name: folder.name,
          ...(folder.description ? { description: folder.description } : {}),
          item: buildItems(folder.id),
        }));

        const childRequests = (requestsByFolder.get(key) ?? []).map((requestItem) =>
          toPostmanRequestItem(requestItem),
        );

        return [...childFolders, ...childRequests];
      };

      const environment = (Array.isArray(environments) ? environments : []).find(
        (item) => item.id === collection.environment_id,
      );

      const postmanCollection = {
        info: {
          _postman_id: crypto.randomUUID(),
          name: collection.name,
          description: collection.description || "",
          schema: "https://schema.getpostman.com/json/collection/v2.1.0/collection.json",
        },
        item: buildItems(null),
        variable: (environment?.variables ?? []).map((item) => ({
          key: item.key,
          value: item.value,
          type: "string",
        })),
      };

      const blob = new Blob([JSON.stringify(postmanCollection, null, 2)], { type: "application/json" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `${collection.name || "collection"}.postman_collection.json`;
      a.click();
      URL.revokeObjectURL(url);
      toast("success", "Collection exported");
    } catch {
      toast("error", "Failed to export collection");
    }
  }

  async function handleShareCollection(id: string) {
    try {
      const res = await fetch(`/api/collections/${id}/share`, {
        method: "POST",
      });
      if (!res.ok) throw new Error("Failed");
      const payload = (await res.json().catch(() => null)) as { data?: { url?: string } } | null;
      const shareUrl = payload?.data?.url;
      if (!shareUrl) throw new Error("Invalid share URL");

      try {
        await navigator.clipboard.writeText(shareUrl);
        toast("success", "Share link copied to clipboard");
      } catch {
        window.prompt("Copy this share link", shareUrl);
      }
    } catch {
      toast("error", "Failed to create share link");
    }
  }

  async function handleRenameFolder(id: string) {
    const folder = safeFolders.find((f) => f.id === id);
    if (!folder) return;
    const newName = prompt("Rename folder:", folder.name);
    if (!newName || newName === folder.name) return;
    try {
      const res = await fetch(`/api/documentation/folders/${id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: newName }),
      });
      if (!res.ok) throw new Error("Failed");
      const { data } = await res.json();
      const store = useWorkspaceStore.getState();
      const current = Array.isArray(store.folders) ? store.folders : [];
      store.setFolders(current.map((f) => (f.id === id ? { ...f, ...data } : f)));
      toast("success", "Folder renamed");
    } catch {
      toast("error", "Failed to rename folder");
    }
  }

  async function handleRenameRequest(id: string) {
    const req = safeRequests.find((r) => r.id === id);
    if (!req) return;
    const newName = prompt("Rename request:", req.name);
    if (!newName || newName === req.name) return;
    try {
      const res = await fetch(`/api/requests/${id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: newName }),
      });
      if (!res.ok) throw new Error("Failed");
      const { data } = await res.json();
      const store = useWorkspaceStore.getState();
      const current = Array.isArray(store.requests) ? store.requests : [];
      store.setRequests(current.map((r) => (r.id === id ? { ...r, ...data } : r)));
      toast("success", "Request renamed");
    } catch {
      toast("error", "Failed to rename request");
    }
  }

  async function handleDuplicateRequest(id: string) {
    const req = safeRequests.find((r) => r.id === id);
    if (!req) return;
    try {
      const res = await fetch("/api/requests", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          collectionId: req.collection_id,
          folderId: req.folder_id,
          name: `${req.name} (Copy)`,
          method: req.method,
          url: req.url,
        }),
      });
      if (!res.ok) throw new Error("Failed");
      const { data } = await res.json();
      if (!data?.id) throw new Error("Invalid response");
      const store = useWorkspaceStore.getState();
      store.setRequests([...(Array.isArray(store.requests) ? store.requests : []), data]);
      toast("success", "Request duplicated");
    } catch {
      toast("error", "Failed to duplicate request");
    }
  }
}

"use client";

import type { ReactElement } from "react";
import Link from "next/link";
import { useSession, signOut } from "next-auth/react";
import { useWorkspaceStore, createDefaultBuilder } from "@/stores/workspace-store";
import { useKeyboardShortcuts } from "@/hooks/useKeyboardShortcuts";
import { useToast } from "@/hooks/useToast";
import { useTheme } from "@/components/providers/ThemeProvider";
import { Sidebar } from "./Sidebar";
import { RequestTabs } from "./RequestTabs";
import { RequestEditor } from "./RequestEditor";
import { ResponseViewer } from "./ResponseViewer";
import { StatusBar } from "./StatusBar";
import { ToastContainer } from "@/components/ui/ToastContainer";
import type { WorkspaceInitialData } from "@/types";
import { useEffect, useMemo, useCallback, useRef, useState } from "react";

interface WorkspaceLayoutProps {
  initialData: WorkspaceInitialData;
}

export function WorkspaceLayout({ initialData }: WorkspaceLayoutProps): ReactElement {
  const loadInitialData = useWorkspaceStore((s) => s.loadInitialData);
  const tabs = useWorkspaceStore((s) => s.tabs);
  const activeTabId = useWorkspaceStore((s) => s.activeTabId);
  const openTab = useWorkspaceStore((s) => s.openTab);
  const closeTab = useWorkspaceStore((s) => s.closeTab);
  const sidebarCollapsed = useWorkspaceStore((s) => s.sidebarCollapsed);
  const responseHeight = useWorkspaceStore((s) => s.responseHeight);
  const setResponseHeight = useWorkspaceStore((s) => s.setResponseHeight);
  const { toast } = useToast();
  const loaded = useRef(false);

  useEffect(() => {
    if (!loaded.current) {
      loadInitialData(initialData);
      loaded.current = true;
    }
  }, [initialData, loadInitialData]);

  const safeTabs = Array.isArray(tabs) ? tabs : [];

  const activeTab = useMemo(
    () => safeTabs.find((t) => t.id === activeTabId) ?? safeTabs[0] ?? null,
    [safeTabs, activeTabId],
  );

  const shortcuts = useMemo(
    () => ({
      "ctrl+n": () => openTab(null, createDefaultBuilder()),
      "ctrl+w": () => { if (activeTabId) closeTab(activeTabId); },
      "ctrl+s": () => { toast("info", "Saving…"); },
    }),
    [openTab, closeTab, activeTabId, toast],
  );
  useKeyboardShortcuts(shortcuts);

  const onResizeResponse = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault();
      const startY = e.clientY;
      const startH = responseHeight;
      function onMove(ev: MouseEvent) {
        const delta = startY - ev.clientY;
        setResponseHeight(Math.max(100, Math.min(600, startH + delta)));
      }
      function onUp() {
        window.removeEventListener("mousemove", onMove);
        window.removeEventListener("mouseup", onUp);
      }
      window.addEventListener("mousemove", onMove);
      window.addEventListener("mouseup", onUp);
    },
    [responseHeight, setResponseHeight],
  );

  const { data: session } = useSession();
  const { theme, toggleTheme } = useTheme();
  const [profileOpen, setProfileOpen] = useState(false);

  return (
    <div className="pm-app">
      {/* ── Top bar ── */}
      <div className="pm-topbar">
        <div className="pm-topbar-logo">
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none">
            <path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
          Octoman
        </div>
        <div className="pm-topbar-actions">
          {/* Workspace name */}
          <span style={{ fontSize: 11, color: "var(--muted)", marginRight: 4 }}>
            {session?.user?.name ? `${session.user.name}'s Workspace` : "Workspace"}
          </span>

          {/* Dark/Light toggle */}
          <button
            className="pm-btn pm-btn-secondary pm-theme-btn"
            style={{ height: 30, width: 30, padding: 0, display: "flex", alignItems: "center", justifyContent: "center" }}
            onClick={toggleTheme}
            title={theme === "dark" ? "Switch to Light" : "Switch to Dark"}
          >
            {theme === "dark" ? (
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
                <circle cx="12" cy="12" r="5" /><line x1="12" y1="1" x2="12" y2="3" /><line x1="12" y1="21" x2="12" y2="23" /><line x1="4.22" y1="4.22" x2="5.64" y2="5.64" /><line x1="18.36" y1="18.36" x2="19.78" y2="19.78" /><line x1="1" y1="12" x2="3" y2="12" /><line x1="21" y1="12" x2="23" y2="12" /><line x1="4.22" y1="19.78" x2="5.64" y2="18.36" /><line x1="18.36" y1="5.64" x2="19.78" y2="4.22" />
              </svg>
            ) : (
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round">
                <path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z" />
              </svg>
            )}
          </button>

          {/* Settings (Admin only) */}
          {session?.user?.role === "Admin" && (
            <Link href="/settings" className="pm-btn pm-btn-secondary" style={{ height: 30, fontSize: 11 }}>
              ⚙ Settings
            </Link>
          )}

          {/* Profile dropdown */}
          <div style={{ position: "relative" }}>
            <button
              className="pm-topbar-profile"
              onClick={() => setProfileOpen(!profileOpen)}
            >
              <span className="pm-topbar-avatar">{(session?.user?.name ?? "U").charAt(0).toUpperCase()}</span>
              <span className="pm-topbar-name">{session?.user?.name ?? "User"}</span>
              <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                <polyline points="6 9 12 15 18 9" />
              </svg>
            </button>
            {profileOpen && (
              <>
                <div style={{ position: "fixed", inset: 0, zIndex: 99 }} onClick={() => setProfileOpen(false)} />
                <div className="pm-profile-dropdown">
                  <div className="pm-profile-header">
                    <span className="pm-topbar-avatar" style={{ width: 32, height: 32, fontSize: 14 }}>{(session?.user?.name ?? "U").charAt(0).toUpperCase()}</span>
                    <div>
                      <div style={{ fontWeight: 600, fontSize: 13 }}>{session?.user?.name ?? "User"}</div>
                      <div style={{ fontSize: 11, color: "var(--muted)" }}>{session?.user?.email ?? ""}</div>
                    </div>
                  </div>
                  <div className="pm-profile-role">
                    <span style={{ fontSize: 11, color: "var(--text-secondary)" }}>Role:</span>
                    <span className={`settings-role-chip settings-role-${(session?.user?.role ?? "viewer").toLowerCase()}`} style={{ fontSize: 10 }}>
                      {session?.user?.role ?? "Viewer"}
                    </span>
                  </div>
                  <div className="pm-context-separator" />
                  <Link href="/settings" className="pm-context-item" onClick={() => setProfileOpen(false)}>
                    Settings
                  </Link>
                  <button
                    className="pm-context-item pm-context-item-danger"
                    onClick={() => void signOut({ callbackUrl: "/login" })}
                  >
                    Logout
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      </div>

      {/* ── Body (sidebar + workspace) ── */}
      <div className="pm-body">
        {!sidebarCollapsed && <Sidebar />}

        <div className="pm-workspace">
          <RequestTabs />

          {activeTab ? (
            <>
              <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", minHeight: 0 }}>
                <RequestEditor tab={activeTab} />
              </div>
              <div className="pm-resize-handle-v" onMouseDown={onResizeResponse} />
              <div className="pm-response-panel" style={{ height: responseHeight, flexShrink: 0 }}>
                <ResponseViewer tab={activeTab} />
              </div>
            </>
          ) : (
            <div className="pm-empty" style={{ flex: 1 }}>
              <svg width="56" height="56" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.2" style={{ color: "var(--border-strong)" }}>
                <path d="M13 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V9z" />
                <polyline points="13 2 13 9 20 9" />
              </svg>
              <p style={{ fontSize: 15, fontWeight: 600, color: "var(--text-secondary)" }}>No request open</p>
              <p>Create a new tab with <kbd style={{ padding: "2px 6px", borderRadius: 4, border: "1px solid var(--border)", background: "var(--surface)", fontSize: 11 }}>Ctrl+N</kbd> or select a request from the sidebar</p>
            </div>
          )}
        </div>
      </div>

      {/* ── Status bar ── */}
      <StatusBar />

      <ToastContainer />
    </div>
  );
}

"use client";

import { create } from "zustand";
import type {
  BuilderState,
  CollectionDto,
  DocumentationFolderDto,
  EnvironmentDto,
  ExecuteResultState,
  HistoryDto,
  HttpMethod,
  KeyValuePair,
  MockServerDto,
  MonitorDto,
  OrganizationDto,
  AdminUserDto,
  RequestDto,
  RequestType,
  SidebarTab,
  TabState,
  TestResult,
  ToastMessage,
  ToastType,
  WorkspaceInitialData,
} from "@/types";

/* ------------------------------------------------------------------ */
/*  Default builder                                                    */
/* ------------------------------------------------------------------ */

export function createDefaultBuilder(
  collectionId: string | null = null,
  folderId: string | null = null,
): BuilderState {
  return {
    id: null,
    name: "",
    description: "",
    request_type: "http",
    method: "GET",
    url: "",
    query_params: [],
    headers: [{ key: "Content-Type", value: "application/json", enabled: true }],
    bodyMode: "raw",
    bodyRawLanguage: "json",
    bodyRaw: "",
    bodyForm: [],
    auth: {
      type: "none",
      basic: { username: "", password: "" },
      bearerToken: "",
      apiKey: { key: "", value: "", addTo: "header" },
    },
    preRequestScript: "",
    testScript: "",
    graphqlQuery: "",
    graphqlVariables: "",
    collectionId,
    folderId,
    sort_order: 0,
    _dirty: false,
  };
}

let _tabCounter = 0;
function nextTabId(): string {
  return `tab_${++_tabCounter}_${Date.now()}`;
}

export function createTab(requestId: string | null = null, builder?: BuilderState): TabState {
  return {
    id: nextTabId(),
    requestId,
    builder: builder ?? createDefaultBuilder(),
    responseViewTab: "body",
    executeResult: null,
    testResults: [],
    consoleOutput: [],
    isExecuting: false,
  };
}

/* ------------------------------------------------------------------ */
/*  Store                                                              */
/* ------------------------------------------------------------------ */

export interface WorkspaceStore {
  /* ---- workspace data ---- */
  collections: CollectionDto[];
  requests: RequestDto[];
  environments: EnvironmentDto[];
  history: HistoryDto[];
  folders: DocumentationFolderDto[];
  users: AdminUserDto[];
  organization: OrganizationDto | null;
  mockServers: MockServerDto[];
  monitors: MonitorDto[];

  /* ---- tabs ---- */
  tabs: TabState[];
  activeTabId: string | null;

  /* ---- sidebar ---- */
  sidebarTab: SidebarTab;
  sidebarWidth: number;
  expandedCollectionIds: Record<string, boolean>;
  expandedFolderIds: Record<string, boolean>;
  treeSearch: string;

  /* ---- environment ---- */
  selectedEnvironmentId: string;

  /* ---- toasts ---- */
  toasts: ToastMessage[];

  /* ---- flags ---- */
  sidebarCollapsed: boolean;
  responseHeight: number;

  /* ---- actions: data ---- */
  setCollections: (c: CollectionDto[]) => void;
  setRequests: (r: RequestDto[]) => void;
  setEnvironments: (e: EnvironmentDto[]) => void;
  setHistory: (h: HistoryDto[]) => void;
  setFolders: (f: DocumentationFolderDto[]) => void;
  setUsers: (u: AdminUserDto[]) => void;
  setOrganization: (o: OrganizationDto | null) => void;
  setMockServers: (m: MockServerDto[]) => void;
  setMonitors: (m: MonitorDto[]) => void;
  loadInitialData: (data: WorkspaceInitialData) => void;

  /* ---- actions: tabs ---- */
  openTab: (requestId?: string | null, builder?: BuilderState) => string;
  closeTab: (tabId: string) => void;
  setActiveTab: (tabId: string) => void;
  updateTabBuilder: (tabId: string, partial: Partial<BuilderState>) => void;
  updateTab: (tabId: string, partial: Partial<TabState>) => void;
  markTabDirty: (tabId: string) => void;
  markTabClean: (tabId: string) => void;

  /* ---- actions: sidebar ---- */
  setSidebarTab: (tab: SidebarTab) => void;
  setSidebarWidth: (w: number) => void;
  toggleSidebar: () => void;
  toggleCollection: (id: string) => void;
  toggleFolder: (id: string) => void;
  setTreeSearch: (q: string) => void;
  expandAll: () => void;
  collapseAll: () => void;

  /* ---- actions: environment ---- */
  setSelectedEnvironmentId: (id: string) => void;

  /* ---- actions: response ---- */
  setResponseHeight: (h: number) => void;

  /* ---- actions: toasts ---- */
  addToast: (type: ToastType, title: string, description?: string) => void;
  removeToast: (id: string) => void;
}

export const useWorkspaceStore = create<WorkspaceStore>((set, get) => ({
  /* ---- workspace data ---- */
  collections: [],
  requests: [],
  environments: [],
  history: [],
  folders: [],
  users: [],
  organization: null,
  mockServers: [],
  monitors: [],

  /* ---- tabs ---- */
  tabs: [createTab()],
  activeTabId: null,

  /* ---- sidebar ---- */
  sidebarTab: "collections",
  sidebarWidth: 280,
  expandedCollectionIds: {},
  expandedFolderIds: {},
  treeSearch: "",

  /* ---- environment ---- */
  selectedEnvironmentId: "",

  /* ---- toasts ---- */
  toasts: [],

  /* ---- flags ---- */
  sidebarCollapsed: false,
  responseHeight: 300,

  /* ---- actions: data ---- */
  setCollections: (c) => set({ collections: Array.isArray(c) ? c : [] }),
  setRequests: (r) => set({ requests: Array.isArray(r) ? r : [] }),
  setEnvironments: (e) => set({ environments: Array.isArray(e) ? e : [] }),
  setHistory: (h) => set({ history: Array.isArray(h) ? h : [] }),
  setFolders: (f) => set({ folders: Array.isArray(f) ? f : [] }),
  setUsers: (u) => set({ users: Array.isArray(u) ? u : [] }),
  setOrganization: (o) => set({ organization: o }),
  setMockServers: (m) => set({ mockServers: Array.isArray(m) ? m : [] }),
  setMonitors: (m) => set({ monitors: Array.isArray(m) ? m : [] }),
  loadInitialData: (data) => {
    const collections = Array.isArray(data.collections) ? data.collections : [];
    const requests = Array.isArray(data.requests) ? data.requests : [];
    const environments = Array.isArray(data.environments) ? data.environments : [];
    const historyArr = Array.isArray(data.history) ? data.history : [];
    const folders = Array.isArray(data.folders) ? data.folders : [];
    const users = Array.isArray(data.users) ? data.users : [];
    const defaultEnv = environments.find((e) => e.is_default);
    set({
      collections,
      requests,
      environments,
      history: historyArr,
      folders,
      users,
      organization: data.organization ?? null,
      selectedEnvironmentId: defaultEnv?.id ?? "",
    });
    // Initialize first tab if we have only the initial empty tab
    const { tabs, activeTabId } = get();
    if (tabs.length === 1 && !activeTabId) {
      set({ activeTabId: tabs[0].id });
    }
  },

  /* ---- actions: tabs ---- */
  openTab: (requestId, builder) => {
    const { tabs } = get();
    // If a request is already open in a tab, activate it
    if (requestId) {
      const existing = tabs.find((t) => t.requestId === requestId);
      if (existing) {
        set({ activeTabId: existing.id });
        return existing.id;
      }
    }
    const tab = createTab(requestId, builder);
    set((s) => ({
      tabs: [...s.tabs, tab],
      activeTabId: tab.id,
    }));
    return tab.id;
  },
  closeTab: (tabId) => {
    const { tabs, activeTabId } = get();
    if (tabs.length <= 1) {
      // Always keep at least one tab
      const fresh = createTab();
      set({ tabs: [fresh], activeTabId: fresh.id });
      return;
    }
    const idx = tabs.findIndex((t) => t.id === tabId);
    const remaining = tabs.filter((t) => t.id !== tabId);
    let nextActive = activeTabId;
    if (activeTabId === tabId) {
      nextActive = remaining[Math.min(idx, remaining.length - 1)]?.id ?? remaining[0]?.id ?? null;
    }
    set({ tabs: remaining, activeTabId: nextActive });
  },
  setActiveTab: (tabId) => set({ activeTabId: tabId }),
  updateTabBuilder: (tabId, partial) =>
    set((s) => ({
      tabs: s.tabs.map((t) =>
        t.id === tabId
          ? { ...t, builder: { ...t.builder, ...partial, _dirty: true } }
          : t,
      ),
    })),
  updateTab: (tabId, partial) =>
    set((s) => ({
      tabs: s.tabs.map((t) => (t.id === tabId ? { ...t, ...partial } : t)),
    })),
  markTabDirty: (tabId) =>
    set((s) => ({
      tabs: s.tabs.map((t) =>
        t.id === tabId ? { ...t, builder: { ...t.builder, _dirty: true } } : t,
      ),
    })),
  markTabClean: (tabId) =>
    set((s) => ({
      tabs: s.tabs.map((t) =>
        t.id === tabId ? { ...t, builder: { ...t.builder, _dirty: false } } : t,
      ),
    })),

  /* ---- actions: sidebar ---- */
  setSidebarTab: (tab) => set({ sidebarTab: tab }),
  setSidebarWidth: (w) => set({ sidebarWidth: w }),
  toggleSidebar: () => set((s) => ({ sidebarCollapsed: !s.sidebarCollapsed })),
  toggleCollection: (id) =>
    set((s) => ({
      expandedCollectionIds: {
        ...s.expandedCollectionIds,
        [id]: !s.expandedCollectionIds[id],
      },
    })),
  toggleFolder: (id) =>
    set((s) => ({
      expandedFolderIds: {
        ...s.expandedFolderIds,
        [id]: !s.expandedFolderIds[id],
      },
    })),
  setTreeSearch: (q) => set({ treeSearch: q }),
  expandAll: () => {
    const { collections, folders } = get();
    const cMap: Record<string, boolean> = {};
    const fMap: Record<string, boolean> = {};
    collections.forEach((c) => { cMap[c.id] = true; });
    folders.forEach((f) => { fMap[f.id] = true; });
    set({ expandedCollectionIds: cMap, expandedFolderIds: fMap });
  },
  collapseAll: () => set({ expandedCollectionIds: {}, expandedFolderIds: {} }),

  /* ---- actions: environment ---- */
  setSelectedEnvironmentId: (id) => set({ selectedEnvironmentId: id }),

  /* ---- actions: response ---- */
  setResponseHeight: (h) => set({ responseHeight: h }),

  /* ---- actions: toasts ---- */
  addToast: (type, title, description) => {
    const id = `toast_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
    const toast: ToastMessage = { id, type, title, description, duration: 4000 };
    set((s) => ({ toasts: [...s.toasts, toast] }));
    setTimeout(() => {
      set((s) => ({ toasts: s.toasts.filter((t) => t.id !== id) }));
    }, toast.duration);
  },
  removeToast: (id) => set((s) => ({ toasts: s.toasts.filter((t) => t.id !== id) })),
}));

import { NextResponse } from "next/server";
import { Types } from "mongoose";
import { z } from "zod";

import { connectToDatabase } from "@/lib/db/connect";
import { SavedRequestModel } from "@/lib/db/models/SavedRequest";
import { EnvironmentModel } from "@/lib/db/models/Environment";
import { RunResultModel } from "@/lib/db/models/RunResult";
import { apiError, apiException, readJsonBody, headersToRecord, normalizeHeaders, parseObjectId } from "@/lib/server/api";
import { getTenantContext } from "@/lib/server/auth";
import { normalizeAuthConfig, createDefaultAuthConfig, normalizeBodyMode, normalizeBodyForm } from "@/lib/server/request-contract";
import { interpolateString, interpolateHeaders, interpolateKeyValuePairs, variablesToMap } from "@/lib/server/interpolate";
import { executeScript } from "@/lib/scripting/pm-api";
import type { TestResult } from "@/types";

export const runtime = "nodejs";

const runSchema = z.object({
  collection_id: z.string().trim().min(1),
  environment_id: z.string().trim().optional().nullable(),
  iterations: z.number().int().min(1).max(100).default(1),
  delay_ms: z.number().int().min(0).max(10000).default(0),
});

export async function POST(request: Request) {
  const context = await getTenantContext();
  if (!context) return apiError("Unauthorized.", 401);

  try {
    const payload = await readJsonBody<unknown>(request);
    const parsed = runSchema.safeParse(payload);
    if (!parsed.success) return apiError("Invalid payload.", 422, "VALIDATION_ERROR", parsed.error.flatten());

    await connectToDatabase();

    const collectionId = parseObjectId(parsed.data.collection_id);
    if (!collectionId) return apiError("Invalid collection ID.", 422);

    const envId = parseObjectId(parsed.data.environment_id ?? null);
    let variableMap: Record<string, string> = {};

    if (envId) {
      const env = await EnvironmentModel.findOne({ _id: envId, tenant_id: context.tenantId }).lean();
      if (env) variableMap = variablesToMap(env.variables);
    }

    const requests = await SavedRequestModel.find({
      collection_id: collectionId,
      tenant_id: context.tenantId,
    })
      .sort({ sort_order: 1, createdAt: 1 })
      .lean();

    const results: {
      iteration: number;
      request_id: string;
      request_name: string;
      method: string;
      url: string;
      status: number | null;
      duration_ms: number;
      passed: boolean;
      error: string | null;
      test_results: TestResult[];
    }[] = [];

    let totalPassed = 0;
    let totalFailed = 0;
    const startedAt = new Date();

    for (let iter = 1; iter <= parsed.data.iterations; iter++) {
      for (const req of requests) {
        const interpolatedUrl = interpolateString(req.url, variableMap);
        const normalizedHeaders = normalizeHeaders(req.headers ?? []);
        const interpolatedHeaders = interpolateHeaders(normalizedHeaders, variableMap);
        const headersRecord = headersToRecord(interpolatedHeaders);
        const bodyMode = normalizeBodyMode(req.body_mode, req.method);
        const rawBody = interpolateString(req.body_raw ?? req.body ?? "", variableMap);

        let bodyToSend: BodyInit | undefined;
        if (bodyMode === "raw" && rawBody.trim()) {
          bodyToSend = rawBody;
        } else if (bodyMode === "x-www-form-urlencoded") {
          const formPairs = interpolateKeyValuePairs(normalizeBodyForm(req.body_form), variableMap).filter((f) => f.enabled !== false);
          const params = new URLSearchParams();
          formPairs.forEach((f) => params.append(f.key, f.value));
          bodyToSend = params;
        }

        const start = Date.now();
        let status: number | null = null;
        let error: string | null = null;
        let responseBody = "";
        let responseHeaders: { key: string; value: string }[] = [];

        try {
          const parsedUrl = new URL(interpolatedUrl);
          const auth = normalizeAuthConfig(req.auth ?? createDefaultAuthConfig());
          let finalHeaders = { ...headersRecord };

          if (auth.type === "bearer" && auth.bearerToken) {
            finalHeaders.Authorization = `Bearer ${interpolateString(auth.bearerToken, variableMap)}`;
          } else if (auth.type === "basic") {
            const token = Buffer.from(`${interpolateString(auth.basic.username, variableMap)}:${interpolateString(auth.basic.password, variableMap)}`).toString("base64");
            finalHeaders.Authorization = `Basic ${token}`;
          }

          const controller = new AbortController();
          const timeout = setTimeout(() => controller.abort(), 30000);

          const resp = await fetch(parsedUrl.toString(), {
            method: req.method,
            headers: finalHeaders,
            body: bodyToSend,
            cache: "no-store",
            signal: controller.signal,
          });

          clearTimeout(timeout);
          status = resp.status;
          responseBody = await resp.text();
          resp.headers.forEach((v, k) => responseHeaders.push({ key: k, value: v }));
        } catch (err) {
          error = err instanceof Error ? err.message : String(err);
        }

        const durationMs = Date.now() - start;

        // Run test scripts
        let testResults: TestResult[] = [];
        const testScript = req.test_script ?? "";
        if (testScript.trim() && status !== null) {
          const scriptResult = executeScript(testScript, {
            response: { status, statusText: "", headers: responseHeaders, body: responseBody, durationMs },
            envVariables: variableMap,
          });
          testResults = scriptResult.testResults;
        }

        const allPassed = !error && (status !== null && status < 400) && testResults.every((t) => t.passed);
        if (allPassed) totalPassed++;
        else totalFailed++;

        results.push({
          iteration: iter,
          request_id: req._id.toString(),
          request_name: req.name,
          method: req.method,
          url: interpolatedUrl,
          status,
          duration_ms: durationMs,
          passed: allPassed,
          error,
          test_results: testResults,
        });

        // Delay between requests
        if (parsed.data.delay_ms > 0) {
          await new Promise((resolve) => setTimeout(resolve, parsed.data.delay_ms));
        }
      }
    }

    const total = totalPassed + totalFailed;
    const runDoc = await RunResultModel.create({
      _id: new Types.ObjectId(),
      tenant_id: context.tenantId,
      collection_id: collectionId,
      environment_id: envId,
      total,
      passed: totalPassed,
      failed: totalFailed,
      iterations: parsed.data.iterations,
      delay_ms: parsed.data.delay_ms,
      status: "completed",
      results,
      started_at: startedAt,
      completed_at: new Date(),
    });

    return NextResponse.json({
      run: {
        id: runDoc._id.toString(),
        total,
        passed: totalPassed,
        failed: totalFailed,
        iterations: parsed.data.iterations,
        status: "completed",
        results,
      },
    });
  } catch (error) {
    return apiException(error);
  }
}

"use client";

import { use, useEffect, useState, type ReactElement } from "react";
import Link from "next/link";

export const dynamic = "force-dynamic";

interface SharedCollectionInfo {
  id: string;
  name: string;
  description?: string;
  slug: string;
}

interface SharedFolder {
  id: string;
  collectionId: string | null;
  parentId: string | null;
  name: string;
  description?: string;
}

interface SharedRequest {
  id: string;
  collectionId: string | null;
  folderId: string | null;
  name: string;
  description?: string;
  method: string;
  url: string;
}

interface SharedPayload {
  schemaVersion: number;
  exportedAt: string;
  shared: boolean;
  collection: SharedCollectionInfo;
  folders: SharedFolder[];
  requests: SharedRequest[];
}

type SelectedItem = 
  | { type: "collection" }
  | { type: "folder"; folderId: string }
  | { type: "request"; requestId: string };

function getMethodColor(method: string): string {
  const m = method.toUpperCase();
  switch (m) {
    case "GET": return "#61affe";
    case "POST": return "#49cc90";
    case "PUT": return "#fca130";
    case "PATCH": return "#50e3c2";
    case "DELETE": return "#f93e3e";
    case "HEAD": return "#9012fe";
    case "OPTIONS": return "#0ed7b5";
    default: return "#999";
  }
}

interface SidebarItemProps {
  item: SharedFolder | SharedRequest | { type: "collection"; name: string };
  isSelected: boolean;
  isFolder: boolean;
  isExpanded: boolean;
  hasChildren: boolean;
  onSelect: () => void;
  onToggle: () => void;
  depth: number;
  payload: SharedPayload;
}

function SidebarItem({
  item,
  isSelected,
  isFolder,
  isExpanded,
  hasChildren,
  onSelect,
  onToggle,
  depth,
  payload,
}: {
  item: SharedFolder | SharedRequest | { type: "collection"; name: string };
  isSelected: boolean;
  isFolder: boolean;
  isExpanded: boolean;
  hasChildren: boolean;
  onSelect: () => void;
  onToggle: () => void;
  depth: number;
  payload: SharedPayload;
}): ReactElement {
  const name = "name" in item ? item.name : "Unknown";
  const isRequest = "method" in item;
  const method = isRequest ? (item as SharedRequest).method : null;

  return (
    <div style={{ marginLeft: depth * 16 }}>
      <div
        onClick={onSelect}
        style={{
          display: "flex",
          alignItems: "center",
          gap: 6,
          padding: "6px 8px",
          borderRadius: 4,
          cursor: "pointer",
          background: isSelected ? "rgba(73, 204, 144, 0.1)" : "transparent",
          borderLeft: isSelected ? `3px solid #49cc90` : "3px solid transparent",
          fontSize: 12,
          color: isSelected ? "var(--text)" : "var(--text-secondary)",
          fontWeight: isSelected ? 600 : 400,
          userSelect: "none",
          transition: "all 0.15s",
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.background = isSelected
            ? "rgba(73, 204, 144, 0.15)"
            : "rgba(255, 255, 255, 0.05)";
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.background = isSelected
            ? "rgba(73, 204, 144, 0.1)"
            : "transparent";
        }}
      >
        {isFolder && hasChildren ? (
          <button
            onClick={(e) => {
              e.stopPropagation();
              onToggle();
            }}
            style={{
              background: "none",
              border: "none",
              padding: 0,
              cursor: "pointer",
              display: "flex",
              alignItems: "center",
              color: "inherit",
              fontSize: 10,
              width: 16,
            }}
          >
            {isExpanded ? "▼" : "▶"}
          </button>
        ) : (
          <span style={{ width: 16 }}>
            {isRequest ? (
              <span
                style={{
                  display: "inline-block",
                  fontSize: 7,
                  fontWeight: 700,
                  color: method ? getMethodColor(method) : "#999",
                  width: "100%",
                  textAlign: "center",
                }}
              >
                {method?.slice(0, 3).toUpperCase()}
              </span>
            ) : (
              <span style={{ fontSize: 12 }}>📁</span>
            )}
          </span>
        )}
        <span style={{ flex: 1, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
          {name}
        </span>
      </div>
    </div>
  );
}

interface FolderTreeProps {
  folders: SharedFolder[];
  requests: SharedRequest[];
  parentId: string | null;
  depth: number;
  selectedItem: SelectedItem;
  onSelectItem: (item: SelectedItem) => void;
  expandedFolders: Set<string>;
  onToggleFolder: (folderId: string) => void;
  payload: SharedPayload;
}

function FolderTree({
  folders,
  requests,
  parentId,
  depth,
  selectedItem,
  onSelectItem,
  expandedFolders,
  onToggleFolder,
  payload,
}: FolderTreeProps): ReactElement {
  const childFolders = folders
    .filter((f) => f.parentId === parentId)
    .sort((a, b) => a.name.localeCompare(b.name));
  const childRequests = requests
    .filter((r) => r.folderId === parentId)
    .sort((a, b) => a.name.localeCompare(b.name));

  return (
    <>
      {childFolders.map((folder) => {
        const folderHasChildren =
          folders.some((f) => f.parentId === folder.id) ||
          requests.some((r) => r.folderId === folder.id);
        const isExpanded = expandedFolders.has(folder.id);
        const isSelected =
          selectedItem.type === "folder" && selectedItem.folderId === folder.id;

        return (
          <div key={folder.id}>
            <SidebarItem
              item={folder}
              isSelected={isSelected}
              isFolder={true}
              isExpanded={isExpanded}
              hasChildren={folderHasChildren}
              onSelect={() => onSelectItem({ type: "folder", folderId: folder.id })}
              onToggle={() => onToggleFolder(folder.id)}
              depth={depth}
              payload={payload}
            />
            {isExpanded && (
              <FolderTree
                folders={folders}
                requests={requests}
                parentId={folder.id}
                depth={depth + 1}
                selectedItem={selectedItem}
                onSelectItem={onSelectItem}
                expandedFolders={expandedFolders}
                onToggleFolder={onToggleFolder}
                payload={payload}
              />
            )}
          </div>
        );
      })}

      {childRequests.map((request) => {
        const isSelected =
          selectedItem.type === "request" && selectedItem.requestId === request.id;

        return (
          <SidebarItem
            key={request.id}
            item={request}
            isSelected={isSelected}
            isFolder={false}
            isExpanded={false}
            hasChildren={false}
            onSelect={() => onSelectItem({ type: "request", requestId: request.id })}
            onToggle={() => {}}
            depth={depth}
            payload={payload}
          />
        );
      })}
    </>
  );
}

function OverviewPanel({
  collection,
  folder,
}: {
  collection: SharedCollectionInfo;
  folder?: SharedFolder;
}): ReactElement {
  const item = folder || collection;
  return (
    <div>
      <h2 style={{ fontSize: 18, marginBottom: 16, fontWeight: 600 }}>
        {item.name}
      </h2>
      {item.description ? (
        <div style={{ fontSize: 13, color: "var(--text-secondary)", lineHeight: 1.6 }}>
          {item.description}
        </div>
      ) : (
        <p style={{ fontSize: 13, color: "var(--muted)" }}>No description available.</p>
      )}
    </div>
  );
}

function RequestDetailsPanel({
  request,
}: {
  request: SharedRequest;
}): ReactElement {
  const methodColor = getMethodColor(request.method);

  return (
    <div>
      <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 20 }}>
        <span
          style={{
            display: "inline-flex",
            alignItems: "center",
            justifyContent: "center",
            width: 40,
            height: 40,
            borderRadius: 4,
            background: `${methodColor}20`,
            color: methodColor,
            fontWeight: 700,
            fontSize: 11,
            fontFamily: "var(--font-mono)",
          }}
        >
          {request.method.toUpperCase()}
        </span>
        <div style={{ flex: 1 }}>
          <h2 style={{ fontSize: 18, marginBottom: 4, fontWeight: 600 }}>
            {request.name}
          </h2>
          {request.description && (
            <p style={{ fontSize: 12, color: "var(--text-secondary)" }}>
              {request.description}
            </p>
          )}
        </div>
      </div>

      {/* URL */}
      <div style={{ marginBottom: 20 }}>
        <h3 style={{ fontSize: 12, fontWeight: 600, marginBottom: 6, color: "var(--muted)" }}>
          URL
        </h3>
        <div
          style={{
            padding: 10,
            background: "var(--surface)",
